(function () {
  'use strict';

  const ROOT_ID = '__vn_ext_root__';
  if (document.getElementById(ROOT_ID)) return;

  // ── Vocabulary data (auto-generated by build_extension.py) ───
  const VOCAB = [{"v":"À","p":"Ah! (surpresa leve)","e":"Ah! (mild surprise)","c":"Interjeição","g":"Interjeição de surpresa ou reconhecimento suave. Invariável, aparece no início da frase. É mais suave que 'Ồ!' — equivale a 'Ah, é mesmo!' Nenhuma flexão possível."},{"v":"Anh","p":"Irmão mais velho / Você (homem mais velho)","e":"Older brother / You (older male)","c":"Pronome","g":"Pronome social para homem levemente mais velho (irmão mais velho, jovem adulto, namorado, colega). Usado como 'você' ao falar COM ele e como 'eu' quando ELE fala ('Anh tên là...'). Par feminino: 'chị'. A pessoa mais nova usa 'em' para si mesma."},{"v":"Anh (nước)","p":"Reino Unido / Inglaterra","e":"United Kingdom / England","c":"Nome","g":"Nome próprio do país. Note a ambiguidade: 'Anh' = pronome social E nome do país — o contexto diferencia. Gentílico: 'người Anh' (britânico/a). Frase padrão: 'Tôi là người Anh' (sou britânico/a)."},{"v":"Ăn","p":"Comer","e":"To eat","c":"Verbo","g":"Verbo invariável — NUNCA conjuga. 'Ăn' serve para eu/você/ele/nós/todos. Use 'sẽ ăn' (futuro: vou comer), 'đang ăn' (presente contínuo: estou comendo), 'đã ăn' (passado: já comi). Estrutura: Pronome + [marcador tempo] + ăn + [objeto]."},{"v":"Ăn tối / Ăn sáng / Ăn trưa","p":"Jantar / Café da manhã / Almoçar","e":"Eat dinner / Eat breakfast / Eat lunch","c":"Verbo","g":"ĂN + período do dia = refeição. ĂN TỐI (jantar — TỐI = noite) | ĂN SÁNG (café da manhã — SÁNG = manhã) | ĂN TRƯA (almoço — TRƯA = meio-dia). Estrutura com ĐÃ...CHƯA: 'Bạn đã ăn tối chưa?' (Você já jantou?). Resposta: 'Tôi ăn rồi' (já comi) / 'Tôi chưa ăn' (ainda não comi). Note: NẤU ĂN = cozinhar — NẤU (cozinhar) + ĂN (para comer)."},{"v":"Bà","p":"Avó / Você (mulher idosa)","e":"Grandmother / You (elderly woman)","c":"Pronome","g":"Pronome social para mulher idosa (avó, senhora). Uma criança ou jovem se refere a si mesma como 'cháu' e chama a senhora de 'bà'. O par masculino é 'ông'. Use 'bà' para qualquer mulher da faixa etária de avó — é sinal de respeito."},{"v":"Bác","p":"Tio/Tia (mais velhos que os pais)","e":"Uncle/Aunt (older than parents)","c":"Pronome","g":"Pronome social neutro (masculino ou feminino) para adulto levemente mais velho que seus pais. Uma criança usa 'cháu' para si e 'bác' para esse adulto. Diferença de 'chú/cô' (irmãos mais NOVOS do pai) e 'cậu/dì' (irmãos mais novos da mãe)."},{"v":"Bạn","p":"Você (mesma idade) / Amigo(a)","e":"You (same age) / Friend","c":"Pronome","g":"Pronome social neutro para pessoa da mesma faixa etária. Também significa 'amigo(a)'. É o pronome mais seguro para iniciantes quando não se conhece a relação de idade. Não tem conotação de gênero."},{"v":"Bận","p":"Ocupado(a)","e":"Busy","c":"Adjetivo","g":"Adjetivo que vem APÓS o sujeito. Para negar: 'Tôi không bận' (não estou ocupado). Pergunta sim/não: 'Anh có bận không?' — a estrutura 'Có...không?' (lit. 'tem/está...não?') é o padrão para qualquer adjetivo. Resposta: 'Có' (sim) ou 'Không' (não)."},{"v":"Ba","p":"Três (3) / Pai (informal)","e":"Three (3) / Dad (informal)","c":"Número","g":"Número cardinal 3. Vem ANTES do classificador + substantivo ao contar: 'ba con mèo' (três gatos), 'ba quyển sách' (três livros). 'Ba' também significa 'pai' informalmente no Sul — no Norte o mais comum é 'bố'."},{"v":"Bảy","p":"Sete (7)","e":"Seven (7)","c":"Número","g":"Número cardinal 7. Invariável. Compostos: 'mười bảy' (17), 'hai mươi bảy' (27), 'bảy mươi' (70), 'bảy trăm' (700). Em qualquer posição, 'bảy' nunca muda."},{"v":"Bố","p":"Pai","e":"Father","c":"Nome","g":"Palavra para pai, predominante no Norte do Vietnã. No Sul: 'ba' ou 'tía'. Para dizer 'meu pai': 'bố tôi' (sem 'của' necessário neste caso). Pronome social: filhos usam 'con' para si e chamam o pai de 'bố'."},{"v":"Bố mẹ","p":"Pais (pai e mãe)","e":"Parents (father and mother)","c":"Substantivo","g":"BỐ MẸ = pais (composto formal do Norte: BỐ = pai + MẸ = mãe). Equivalente do Sul: 'ba má'. Para perguntar: 'Bố mẹ bạn có đi làm không?' (Seus pais trabalham?). Sistema de posse: 'bố mẹ tôi' (meus pais). ĐỀU reforça que ambos fazem a mesma coisa: 'Bố mẹ tôi đều đi làm' (Meus pais ambos trabalham). Compare VỢ CHỒNG (marido e mulher), ÔNG BÀ (avôs)."},{"v":"Bốn","p":"Quatro (4)","e":"Four (4)","c":"Número","g":"Número cardinal 4 — forma base. ATENÇÃO: na posição de unidade em compostos after dezena, 4 pode virar 'tư': '24 = hai mươi tư'. Mas para dezenas redondas mantém 'bốn': '40 = bốn mươi'. Regra: 'tư' SOMENTE na posição de unidade."},{"v":"Bộ phim","p":"Filme","e":"Movie / Film","c":"Substantivo","g":"Substantivo composto: 'bộ' (conjunto/série/classificador para obras) + 'phim' (filme). Em contagem: 'một bộ phim' (um filme). Para elogiar: 'bộ phim này rất hay' (este filme é muito bom — note 'hay' para obras, não 'ngon')."},{"v":"Bức tranh","p":"Quadro / Pintura","e":"Painting / Picture","c":"Substantivo","g":"Substantivo composto: 'bức' (classificador para quadros/pinturas) + 'tranh' (pintura). 'Bức' é o classificador específico: 'một bức tranh' (um quadro). Para elogiar: usa-se 'đẹp' (bonito), não 'hay' (que é para obras de entretenimento)."},{"v":"Bức","p":"Classificador (quadros, fotos, cartas)","e":"Classifier (paintings, photos, letters)","c":"Classificador","g":"BỨC é o classificador para objetos bidimensionais: BỨC TRANH (quadro/pintura), BỨC ẢNH (foto), BỨC THƯ (carta). Estrutura: 'một bức tranh' (um quadro), 'hai bức ảnh' (duas fotos). Não confunda com CON (animais) nem QUẢ (frutas) — cada substantivo tem seu classificador fixo."},{"v":"Bút","p":"Caneta / Lápis","e":"Pen / Pencil","c":"Substantivo","g":"Substantivo para instrumento de escrita. Classificador: 'cái' (para objetos inanimados). 'Một cái bút' = uma caneta. Tipos: 'bút bi' (caneta esferográfica), 'bút chì' (lápis). Posse: 'cái bút của tôi' = minha caneta."},{"v":"Bao nhiêu","p":"Quanto(s)?","e":"How many? / How much?","c":"Interrogativo","g":"Interrogativo para quantidade. Estrutura para perguntar idade: Pronome + bao nhiêu + tuổi? 'Anh bao nhiêu tuổi?' = Quantos anos você tem? Resposta: Pronome + [número] + tuổi. MẤY vs BAO NHIÊU: use MẤY para crianças (números pequenos), BAO NHIÊU para adultos."},{"v":"Bác sĩ","p":"Médico(a)","e":"Doctor","c":"Profissão","g":"Profissão: médico/médica. Com LÀ: 'Tôi là bác sĩ' (Sou médico). Profissões comuns: giáo viên (professor), sinh viên (estudante), bác sĩ (médico), kỹ sư (engenheiro). Ao cumprimentar: 'Chào bác sĩ!' — o título funciona como pronome de respeito."},{"v":"Bây giờ","p":"Agora","e":"Now","c":"Expressão","g":"Expressão temporal para o MOMENTO PRESENTE. INDICADOR de ĐANG (presente contínuo). SISTEMA: HÔM QUA (ontem) → ĐÃ | BÂY GIỜ (agora) → ĐANG | NGÀY MAI (amanhã) → SẼ. Posição preferida: início da frase: 'Bây giờ tôi đang làm...' (Agora estou fazendo...)."},{"v":"Bây giờ là mấy giờ? / Mấy giờ rồi?","p":"Que horas são? (duas formas)","e":"What time is it? (two forms)","c":"Expressão","g":"Duas formas de perguntar as horas: (1) 'Bây giờ là mấy giờ?' — mais completa/formal; (2) 'Mấy giờ rồi?' — mais casual (lit. 'que horas já?'). RỒI = já / partícula de estado atual. Para responder: 'Bây giờ là [número] giờ [minutos].' Exemplos: 'Bây giờ là 9 giờ sáng' (São 9 da manhã) / 'Bây giờ là 8 giờ rưỡi' (São 8 e meia)."},{"v":"Bình thường","p":"Normal / Mais ou menos","e":"Normal / So-so","c":"Adjetivo","g":"Adjetivo para estado neutro — nem bom nem ruim. Resposta honesta para 'Anh có khoẻ không?'. Diferente de 'rất khoẻ' (muito bem). Use com CÒN para devolver: 'Tôi bình thường, còn anh?' (Estou normal, e você?)."},{"v":"Brasil","p":"Brasil","e":"Brazil","c":"Nome","g":"Nome do Brasil em vietnamita. Gentílico: 'người Brasil' (brasileiro/a). Estrutura padrão de nacionalidade: 'Tôi là người Brasil' (Sou brasileiro/a). Ao responder 'Bạn là người nước nào?': 'Tôi là người Brasil.' — Pode-se também dizer 'Tôi đến từ Brasil' (Venho do Brasil). Compare: Anh (UK), Mỹ (EUA), Đức (Alemanha), Trung Quốc (China)."},{"v":"Cái","p":"Classificador (objetos inanimados)","e":"Classifier (inanimate objects)","c":"Classificador","g":"CÁI é o classificador mais comum — usado para a maioria dos objetos inanimados: cái bàn (mesa), cái ghế (cadeira), cái bút (caneta), cái điện thoại (celular). Estrutura: CÁI + substantivo + demonstrativo: 'cái ghế này' (esta cadeira). NÃO use para animais (CON) nem livros (QUYỂN). Em contagem: 'một cái bàn' (uma mesa), 'hai cái ghế' (duas cadeiras)."},{"v":"Cảm ơn","p":"Obrigado(a)","e":"Thank you","c":"Expressão","g":"Expressão de gratidão. Complete com pronome para ser mais gentil: 'Cảm ơn anh!' (obrigado, irmão mais velho). Para agradecer formalmente: 'Xin cảm ơn'. Resposta padrão: 'Không có gì' (de nada) ou 'Không sao' (não tem problema)."},{"v":"Cậu","p":"Tio (irmão mais novo da mãe)","e":"Uncle (mother's younger brother)","c":"Pronome","g":"Pronome para tio materno (mais jovem que a mãe). Sistema familiar: irmãos da mãe = 'cậu' (masc.) / 'dì' (fem.). Irmãos do pai = 'chú' (masc.) / 'cô' (fem.). 'Cậu' também é usado informalmente entre amigos jovens próximos."},{"v":"Cháu","p":"Eu (falando com avós/tios)","e":"I/Me (speaking with elders)","c":"Pronome","g":"Usado como 'eu' por crianças/jovens ao falar com avós, tios ou adultos muito mais velhos. O adulto reciproca: 'cháu' para a criança (como 'você') e 'ông/bà/bác' para si mesmo. Esse sistema de pronomes mostra respeito pela hierarquia familiar."},{"v":"Chào","p":"Oi / Olá","e":"Hi / Hello","c":"Saudação","g":"Saudação básica. SEMPRE seguida de um pronome social para ser respeitosa: 'Chào anh', 'Chào chị', 'Chào bạn'. Usar 'Chào' sozinho é informal/brusco. Para contextos formais ou ao falar com desconhecidos: 'Xin chào + pronome'."},{"v":"Chín","p":"Nove (9)","e":"Nine (9)","c":"Número","g":"Número cardinal 9. Invariável. Compostos: 'mười chín' (19), 'hai mươi chín' (29), 'chín mươi' (90), 'chín trăm' (900). Tôi cẩn thận com o tom: 'chín' (9, tom sắc) vs 'chín' (maduro/cozido, tom sắc também — mesma escrita, mesmo tom, mas contexto diferencia)."},{"v":"Chị","p":"Irmã mais velha","e":"Older sister","c":"Pronome","g":"Pronome para mulher levemente mais velha (irmã mais velha, professora jovem, colega mais velha). Par feminino de 'anh'. A pessoa mais nova usa 'em' para si. 'Chị' como 'eu' quando ela fala: 'Chị tên là Linh'."},{"v":"Chồng","p":"Marido","e":"Husband","c":"Substantivo","g":"VỢ = esposa, CHỒNG = marido. Par conjugal fundamental. 'Kia là chồng tôi' (Aquele é meu marido). Posse: 'chồng của chị ấy' (o marido dela). No casal vietnamita, a esposa chama o marido de 'anh' e ele a chama de 'em' — sistema de pronomes por hierarquia de idade."},{"v":"Chủ Nhật","p":"Domingo","e":"Sunday","c":"Expressão","g":"Único dia que NÃO segue o padrão THỨ + número. CHỦ = senhor/principal, NHẬT = dia/sol (sino-vietnamita). Sistema completo: THỨ HAI (seg) THỨ BA (ter) THỨ TƯ (qua) THỨ NĂM (qui) THỨ SÁU (sex) THỨ BẢY (sáb) CHỦ NHẬT (dom)."},{"v":"Chú","p":"Tio (irmão mais novo do pai)","e":"Uncle (father's younger brother)","c":"Pronome","g":"Pronome para tio paterno mais jovem que o pai. Par masculino de 'cô'. Sistema: irmãos do PAI: 'chú' (mais novo) e 'bác' (mais velho). Irmãos da MÃE: 'cậu' (mais novo) e 'bác' (mais velho)."},{"v":"Con gái","p":"Filha / Menina","e":"Daughter / Girl","c":"Substantivo","g":"CON GÁI = filha ou menina. CON TRAI = filho ou menino. Para perguntar idade de crianças use MẤY: 'Con gái mấy tuổi?' (não BAO NHIÊU). CON também é classificador para animais: 'một con mèo' (um gato). Sistema familiar: vợ/chồng, con trai, con gái."},{"v":"Con trai","p":"Filho / Menino","e":"Son / Boy","c":"Substantivo","g":"CON TRAI = filho ou menino. 'Đây là con trai tôi' (Este é meu filho). 'Cháu 12 tuổi' = ele tem 12 anos. Sistema familiar: VỢ (esposa), CHỒNG (marido), CON TRAI (filho), CON GÁI (filha)."},{"v":"Con","p":"Classificador (animais)","e":"Classifier (animals)","c":"Classificador","g":"CON é o classificador para animais: con mèo (gato), con chó (cachorro), con bò (vaca), con gà (galinha), con cá (peixe). Alguns objetos longos também usam CON: con dao (faca), con đường (estrada). Contagem: số + CON + animal: 'một con mèo' (um gato), 'ba con chó' (três cachorros). CON também é prefixo em CON TRAI (filho) e CON GÁI (filha)."},{"v":"Cô","p":"Tia (irmã do pai)","e":"Aunt (father's sister)","c":"Pronome","g":"Pronome para tia paterna (irmã do pai). 'Cô giáo' = professora jovem ou de ensino fundamental (título de respeito). Sistema: 'cô/chú' para irmãos do pai / 'dì/cậu' para irmãos da mãe."},{"v":"Có","p":"Ter / Haver","e":"To have / There is","c":"Verbo","g":"Verbo altamente versátil com 3 usos: (1) TER — 'Tôi có sách' (tenho um livro); (2) EXISTE/HÁ — 'Có người ở đây' (há alguém aqui); (3) ESTRUTURA DE PERGUNTA — 'Anh có bận không?' (Você está ocupado? — o 'có...không?' cria pergunta sim/não). Muito comum no cotidiano."},{"v":"Còn","p":"E você? / E ainda","e":"And you? / Still","c":"Conjunção","g":"Conjunção com dois usos: (1) 'E você?' após dar informação própria — 'Tôi khỏe, còn anh?' (Estou bem, e você?); (2) ainda/além disso — 'Còn có...' (ainda tem...). O uso (1) é essencial nas saudações vietnamitas para reciprocidade."},{"v":"Công tác","p":"Viagem a trabalho / Missão / A trabalho","e":"Business trip / Work assignment","c":"Expressão","g":"CÔNG TÁC = missão/viagem a serviço do trabalho. Estrutura: ĐI + CÔNG TÁC + lugar: 'đi công tác Hà Nội' (ir a Hanói a trabalho). Diferente de ĐI CHƠI (passear/viajar por lazer) e ĐI DU LỊCH (viajar de turismo). Muito usado no vietnamita formal e profissional."},{"v":"Của","p":"De (indica posse)","e":"Of / Belonging to","c":"Partícula","g":"Partícula de posse. Ordem: [possuído] + của + [possuidor]: 'sách của tôi' (lit. livro de mim = meu livro). Pode ser OMITIDA quando a relação é óbvia entre familiares: 'nhà tôi' (= 'nhà của tôi' = minha casa). Com objetos e pessoas não-familiares, mantenha."},{"v":"Dì","p":"Tia (irmã mais nova da mãe)","e":"Aunt (mother's younger sister)","c":"Pronome","g":"Pronome para tia materna mais jovem que a mãe. Par feminino de 'cậu'. Sistema familiar completo: Irmãos da MÃE: 'cậu' (irmão mais novo) / 'dì' (irmã mais nova) / 'bác' (mais velho que a mãe). Irmãos do PAI: 'chú' / 'cô' / 'bác'."},{"v":"Dạy / Dạy học","p":"Ensinar / Dar aula","e":"To teach","c":"Verbo","g":"DẠY = ensinar. DẠY HỌC = dar aula (forma composta enfatizando o ato de lecionar). TRƯỜNG = escola. TRƯỜNG ĐẠI HỌC = universidade. Estrutura: 'Tôi dạy tiếng Anh' (Ensino inglês). Para perguntar: 'Anh dạy ở đâu?' (Onde você ensina?). Oposto: HỌC (aprender/estudar)."},{"v":"Đã","p":"Já (passado)","e":"Already / Past marker","c":"Partícula","g":"Marcador de tempo PASSADO. Posição: ĐÃ + verbo: 'Tôi đã ăn' (Já comi). HÔM QUA (ontem) → indicador de ĐÃ. SISTEMA: ĐÃ (passado) | ĐANG (contínuo) | SẼ (futuro). O verbo nunca muda. Exemplos: đã ăn (já comi), đã học (já estudei), đã đi (já fui), đã mua (já comprei)."},{"v":"Đang","p":"Está fazendo... (presente contínuo)","e":"Currently / -ing form","c":"Partícula","g":"Marcador de presente CONTÍNUO — ação acontecendo AGORA. ĐANG + verbo. BÂY GIỜ (agora) → indicador de ĐANG. SISTEMA: ĐÃ | ĐANG | SẼ. Exemplos: đang làm việc (está trabalhando), đang học (está estudando), đang ăn (está comendo). O verbo nunca muda de forma."},{"v":"Đâu / Ở đâu","p":"Onde? / Em que lugar? (interrogativo)","e":"Where? (interrogative)","c":"Interrogativo","g":"ĐÂU = 'onde?' (interrogativo de lugar). Ở ĐÂU = 'em que lugar?' (literalmente: ở + đâu). Exemplos: 'Nhà bạn ở đâu?' (Onde é sua casa?), 'Anh đang làm việc ở đâu?' (Onde você está trabalhando?), 'Em đang ở đâu?' (Onde você está?). As interrogativas vão sempre ao FINAL da frase em vietnamita."},{"v":"Đây","p":"Aqui / Este (antes do verbo)","e":"Here / This (before verb)","c":"Demonstrativo","g":"Demonstrativo com dois usos: (1) AQUI — indica posição: 'Tôi ở đây' (estou aqui); (2) ESTE/ESTA — antes de 'là': 'Đây là nhà tôi' (esta é minha casa). Contraste com 'này': 'này' vem APÓS o substantivo ('sách này'), 'đây' vem ANTES do verbo 'là'."},{"v":"Đẹp","p":"Bonito(a)","e":"Beautiful / Pretty","c":"Adjetivo","g":"Adjetivo que vem SEMPRE après o substantivo em vietnamita: 'nhà đẹp' (casa bonita), NUNCA 'đẹp nhà'. Para intensificar: 'rất đẹp' (muito bonito, antes), 'đẹp quá!' (lindo demais!, depois — exclamação), 'đẹp lắm!' (lindíssimo, depois — superlativo)."},{"v":"Đến","p":"Vir / Chegar","e":"To come / To arrive","c":"Verbo","g":"Verbo de movimento EM DIREÇÃO ao local mencionado ou ao falante. Contraste com 'đi' (ir, afastando-se). 'Sẽ đến' = vai vir. 'Đến nhà' = vir à casa. 'Mời anh đến nhà tôi' = convido você a vir à minha casa."},{"v":"Đến từ","p":"Vir de... (origem)","e":"To come from (origin)","c":"Verbo","g":"Expressão verbal de origem: 'đến' (chegar/vir) + 'từ' (de). Estrutura: Pronome + đến từ + [país/local]: 'Tôi đến từ Brazil'. Alternativa sinônima: 'Tôi là người Brazil'. Ambas corretas — a segunda é mais formal."},{"v":"Đi","p":"Ir","e":"To go","c":"Verbo","g":"Verbo de movimento se AFASTANDO (ir). Contraste com 'đến' (vir/chegar). 'Đi thôi!' = vamos! (expressão coloquial para incitar ação). 'Đi đâu?' = onde você vai?. 'Đi học' = ir estudar. Nunca conjuga."},{"v":"Điện thoại","p":"Celular / Telefone","e":"Phone / Mobile","c":"Substantivo","g":"Substantivo composto: 'điện' (elétrico/energia) + 'thoại' (conversa). Literalmente 'conversa elétrica'. Classificador: 'cái' (uma inanimado). 'Điện thoại di động' = celular (lit. telefone móvel). 'Mới' (novo) SEMPRE após: 'điện thoại mới'."},{"v":"Đức","p":"Alemanha","e":"Germany","c":"Nome","g":"Nome próprio da Alemanha. Formação de gentílico padrão: 'người + nome do país': 'người Đức' (alemão/ã). Mesma estrutura para todos os países: 'người Mỹ' (americano), 'người Việt Nam' (vietnamita), 'người Brazil' (brasileiro)."},{"v":"Em","p":"Eu (falando com mais velhos) / Irmão mais novo","e":"I/Me (with elders) / Younger sibling","c":"Pronome","g":"Pronome social para a PESSOA MAIS NOVA na conversa. Usado como 'eu' ao falar com alguém mais velho: 'Em chào anh!' (Eu saúdo você, irmão mais velho!). O mais velho usa 'em' para referir à pessoa mais nova como 'você'. Não tem gênero."},{"v":"Giáo viên","p":"Professor(a)","e":"Teacher","c":"Profissão","g":"Título profissional genérico para professor(a). Formas mais específicas: 'thầy giáo' (professor masculino, afetivo), 'cô giáo' (professora feminina, afetivo), 'giáo sư' (professor universitário/doutor). No sistema vietnamita, professores são tratados com grande respeito."},{"v":"Gặp","p":"Encontrar / Conhecer (pessoalmente)","e":"To meet / Encounter","c":"Verbo","g":"GẶP = encontrar ou conhecer pessoalmente. 'Rất vui được gặp [pronome]' = muito prazer em conhecer você. ĐƯỢC = ter a oportunidade de. Diferença: GẶP (encontro físico/pessoal) vs BIẾT (conhecer sobre algo). 'Hôm nay tôi gặp bạn mới' (Hoje conheci um novo amigo)."},{"v":"Ghế","p":"Cadeira","e":"Chair","c":"Substantivo","g":"Substantivo para cadeira (com encosto). Classificador: 'cái'. 'Một cái ghế' = uma cadeira. Compare: 'ghế' (cadeira) / 'bàn' (mesa) / 'giường' (cama). 'Mời anh ngồi ghế' = por favor, sente-se na cadeira."},{"v":"Gì","p":"O quê? (sempre ao final da frase)","e":"What? (always at end)","c":"Interrogativo","g":"Interrogativo para 'o quê?'. Regra ESSENCIAL: SEMPRE no FINAL da frase, nunca no início como em português. 'Bạn tên là gì?' = lit. 'Você nome é o quê?'. 'Bạn muốn ăn gì?' = 'O que você quer comer?' (lit. Você quer comer o quê?). Colocar 'gì' no início é erro grave."},{"v":"Hai","p":"Dois (2)","e":"Two (2)","c":"Número","g":"Número cardinal 2. Compostos: 'mười hai' (12), 'hai mươi' (20), 'hai trăm' (200), 'hai nghìn' (2.000). Em '20' inicia a série de compostos: 'hai mươi' com 'mươi' (marca de dezena). Invariável em todos os contextos."},{"v":"Hay","p":"Bom / Interessante (livros e filmes)","e":"Good / Interesting (books & films)","c":"Adjetivo","g":"Adjetivo com uso ESPECÍFICO: avalia qualidade de obras (livros, filmes, músicas, histórias). NÃO use para pessoas (use 'tốt') ou comida (use 'ngon'). 'Phim này hay' (este filme é bom), 'bài hát này hay' (esta música é boa). Para intensificar: 'rất hay', 'hay quá!'."},{"v":"Hàn Quốc","p":"Coreia do Sul","e":"South Korea","c":"Nome","g":"Nome da Coreia do Sul (República da Coreia). Gentílico: 'người Hàn Quốc' (coreano/a). TRIỀU TIÊN = Coreia do Norte. Países asiáticos: Hàn Quốc (Coreia do Sul), Nhật Bản (Japão), Trung Quốc (China). Com 'ở' para localização: 'làm việc ở Hàn Quốc'."},{"v":"Hôm kia / Ngày kia","p":"Anteontem / Depois de amanhã","e":"Day before yesterday / Day after tomorrow","c":"Expressão","g":"Linha do tempo completa: HÔM KIA (anteontem) → HÔM QUA (ontem) → HÔM NAY (hoje) → NGÀY MAI (amanhã) → NGÀY KIA (depois de amanhã). KIA = 'lá/distante'. Marcadores: HÔM KIA → ĐÃ (passado); NGÀY KIA → SẼ (futuro). Diferença: HÔM KIA para o passado, NGÀY KIA para o futuro."},{"v":"Hôm nay","p":"Hoje","e":"Today","c":"Expressão","g":"Expressão temporal para 'hoje'. HÔM NAY pode usar qualquer marcador de tempo conforme contexto. Fórmula para datas: 'Hôm nay là [dia da semana], ngày [número] tháng [número].' Contraste: HÔM QUA (ontem), HÔM NAY (hoje), NGÀY MAI (amanhã)."},{"v":"Hôm qua","p":"Ontem","e":"Yesterday","c":"Expressão","g":"Expressão temporal para 'ontem'. HÔM QUA → indicador de ĐÃ (passado). Sistema temporal: HÔM KIA (anteontem) → HÔM QUA (ontem) → HÔM NAY (hoje) → NGÀY MAI (amanhã) → NGÀY KIA (depois de amanhã). Posição preferida: início da frase para ênfase no tempo."},{"v":"Họ và tên","p":"Nome completo (sobrenome + nome)","e":"Full name (surname + given name)","c":"Substantivo","g":"HỌ = sobrenome | TÊN = primeiro nome | VÀ = e. 'Họ và tên' = nome completo. Em vietnamita, o SOBRENOME vem PRIMEIRO: [Họ] + [tên đệm] + [tên]. Exemplo: 'Nguyễn Văn An' — Nguyễn é o sobrenome (họ). Para perguntar apenas o primeiro nome: 'Bạn tên là gì?' Para o nome completo: 'Họ và tên của bạn là gì?'. Compare os dois interrogativos: GÌ ao final em ambos os casos."},{"v":"Khăn","p":"Toalha","e":"Towel","c":"Substantivo","g":"Substantivo para toalha. Classificador: 'cái'. Tipos: 'khăn tắm' (toalha de banho), 'khăn mặt' (toalha de rosto), 'khăn lau' (pano de limpeza), 'khăn quàng' (cachecol). Aparece nos exercícios de pronúncia para a terminação '-ăn'."},{"v":"Khoẻ","p":"Saudável / Bem","e":"Healthy / Well","c":"Adjetivo","g":"Adjetivo de saúde e bem-estar. A pergunta de saudação padrão: 'Anh có khoẻ không?' (Você está bem? — lit. tem saudável não?'). Resposta completa: 'Tôi rất khoẻ. Cảm ơn anh. Còn anh?' (Estou muito bem. Obrigado. E você?). Essencial nas saudações."},{"v":"Kia","p":"Aquele/Aquela (longe, após substantivo)","e":"That (far, after noun)","c":"Demonstrativo","g":"Demonstrativo para algo DISTANTE do falante. Vem SEMPRE APÓS o substantivo: 'ngôi nhà kia' (aquela casa), 'con mèo kia' (aquele gato). Sistema de 3 graus: 'này' (este, perto) / 'đó' (esse, médio) / 'kia' (aquele, longe). Nunca antes do substantivo."},{"v":"Không","p":"Não / Partícula de pergunta sim/não","e":"No / Not / Question particle","c":"Advérbio","g":"Palavra multifuncional: (1) Resposta NÃO: 'Không, tôi không bận'; (2) Negação de verbo/adj: Pronome + không + V/Adj: 'tôi không ăn' (não como), 'không đẹp' (não bonito); (3) Final de pergunta sim/não: 'Anh có bận không?' — o 'không' cria a pergunta, igual ao '吗' do mandarim."},{"v":"Không có gì","p":"De nada","e":"You're welcome / It's nothing","c":"Expressão","g":"Resposta padrão para 'Cảm ơn' (obrigado). Literalmente: não tem nada (a agradecer). Alternativas: 'Không sao' (não tem problema). Sistema: KHÔNG (não) + CÓ (ter) + GÌ (coisa alguma) = de nada. Em situações formais: 'Không có gì, thưa anh/chị' (De nada, senhor/senhora)."},{"v":"Không khoẻ lắm","p":"Não muito bem","e":"Not very well / Not so great","c":"Expressão","g":"Resposta honesta e educada para 'Anh có khoẻ không?'. Padrão: KHÔNG + adjetivo + LẮM = 'não muito + adjetivo'. Funciona com qualquer adjetivo: 'không bận lắm' (não muito ocupado), 'không đẹp lắm' (não muito bonito), 'không ngon lắm' (não muito gostoso). Espectro de respostas para 'como você está?': Rất khoẻ! (ótimo!) → Cũng khoẻ (também bem) → Bình thường (normal) → Không khoẻ lắm (não muito bem) → Không khoẻ (não estou bem)."},{"v":"Là","p":"Ser / Estar (forma única — nunca muda)","e":"To be (single form — never changes)","c":"Verbo","g":"Verbo 'ser/estar' — a forma mais importante do vietnamita. NUNCA conjuga (uma única forma para eu/você/ele/nós/eles/passado/presente/futuro). IMPORTANTE: 'là' é para IDENTIDADE (profissão, nome, origem); para qualidade/estado use adjetivo DIRETO: 'Tôi bận' ✓, NÃO 'Tôi là bận' ✗."},{"v":"Làm việc","p":"Trabalhar","e":"To work","c":"Verbo","g":"LÀM = fazer. VIỆC = trabalho/tarefa. LÀM VIỆC = trabalhar. ĐI LÀM = ir trabalhar (destino/intenção). ĐANG LÀM VIỆC = está trabalhando agora. Para perguntar: 'Anh đang làm việc ở đâu?' (Onde você está trabalhando?). Resposta: 'Tôi đang làm việc ở [lugar]'."},{"v":"Lăm","p":"Cinco (5) — em compostos após dezenas","e":"Five (5) — in compound numbers after tens","c":"Número","g":"Variante de 'năm' (5) usada OBRIGATORIAMENTE na posição de unidade após dezenas: '15 = mười lăm', '25 = hai mươi lăm', '35 = ba mươi lăm'. ERRO COMUM: dizer 'hai mươi năm' para 25 — o correto é 'hai mươi lăm'. 'Năm' só na posição de dezenas e centenas."},{"v":"Lắm","p":"Muito / Bastante (intensificador após adjetivo)","e":"Very much / A lot (after adjective)","c":"Advérbio","g":"Intensificador que vem APÓS o adjetivo. Mais enfático que 'rất' (que vem antes): 'rất đẹp' (muito bonito) vs 'đẹp lắm!' (lindíssimo/MUITO bonito). Comum em exclamações espontâneas, fala casual e para expressar surpresa positiva. 'Lắm' nunca vem antes do adjetivo."},{"v":"Linh","p":"Zero intermediário (em números compostos)","e":"Zero filler in compound numbers","c":"Número","g":"Palavra especial usada quando o dígito das DEZENAS é zero em um número de 3+ dígitos: '101 = một trăm linh một', '305 = ba trăm linh năm'. TEM TOM — 'linh' (ngang/bằng). Em 4 dígitos: '1.005 = một nghìn không trăm linh năm'. Literalmente indica o 'zero' intermediário."},{"v":"Máy tính","p":"Computador","e":"Computer","c":"Substantivo","g":"MÁY TÍNH = computador (lit. 'máquina de calcular': máy=máquina, tính=calcular). Classificador: 'cái'. Frase-exemplo: 'Tôi đã mua máy tính và điện thoại' — ĐÃ para ação passada, VÀ para ligar dois objetos."},{"v":"Ti vi","p":"Televisão / TV","e":"Television / TV","c":"Substantivo","g":"TI VI = televisão (empréstimo do inglês 'TV'). XEM TI VI = assistir TV. Controles: 'bật ti vi' (ligar a TV), 'tắt ti vi' (desligar a TV). Eletrodomésticos e eletrônicos: MÁY TÍNH (computador), ĐIỆN THOẠI (celular), TI VI (TV). Classificador: cái — 'một cái ti vi' (uma TV)."},{"v":"Mấy","p":"Quantos? (números pequenos / crianças)","e":"How many? (small numbers / children's age)","c":"Interrogativo","g":"Interrogativo para NÚMEROS PEQUENOS (1–9) e especialmente idade de CRIANÇAS. MẤY vs BAO NHIÊU: 'Con gái mấy tuổi?' (criança) vs 'Anh bao nhiêu tuổi?' (adulto). Para dia da semana: 'Hôm nay là thứ mấy?' (Que dia da semana é hoje?)."},{"v":"Mẹ","p":"Mãe","e":"Mother","c":"Nome","g":"Palavra para mãe, predominante no Norte. No Sul: 'má'. 'Mẹ tôi' = minha mãe. Pronome social: filhos usam 'con' para si e chamam a mãe de 'mẹ'. Para dizer 'minha mãe é...' não precisa de 'của': 'Mẹ tôi là... ' ✓."},{"v":"Mèo","p":"Gato","e":"Cat","c":"Substantivo","g":"Substantivo para gato. Classificador OBRIGATÓRIO ao contar: 'một con mèo' (um gato), 'hai con mèo' (dois gatos) — 'con' é o classificador para animais. O som 'mèo' imita onomatopeicamente o miado (como 'miau' em português)."},{"v":"Món ăn","p":"Prato / Comida","e":"Dish / Food","c":"Substantivo","g":"Substantivo composto: 'món' (item de uma lista/prato) + 'ăn' (comer). Literalmente 'item para comer'. Para perguntar sobre pratos: 'Bạn thích món ăn gì?' (Qual prato você gosta?). 'Ngon' é o adjetivo correto para comida, não 'hay'."},{"v":"Mời","p":"Convidar / Por favor (polidez)","e":"To invite / Please (polite)","c":"Verbo","g":"Verbo com dois sentidos relacionados: (1) CONVIDAR: 'Tôi muốn mời anh đến nhà tôi' (Quero te convidar para minha casa); (2) POLIDEZ (sinta-se à vontade): 'Mời anh ngồi!' (Por favor, sente-se! — lit. convido você a sentar). Use 'mời' para soar mais educado e hospitaleiro."},{"v":"Mới","p":"Novo(a)","e":"New","c":"Adjetivo","g":"Adjetivo que vem APÓS o substantivo: 'nhà mới' (casa nova), 'điện thoại mới' (celular novo). Contraste com português onde 'novo' pode ir antes: em vietnamita SEMPRE depois. 'Bạn mới' = novo amigo. 'Mới' também pode significar 'acabou de' como advérbio: 'tôi mới đến' (acabei de chegar)."},{"v":"Một","p":"Um (1) — forma base","e":"One (1) — base form","c":"Número","g":"Número cardinal 1 — forma padrão. Use 'một' em posição normal: 'một người' (uma pessoa), 'một trăm' (100), 'một nghìn' (1.000), 'một triệu' (1.000.000). EXCEÇÃO: em compostos após dezenas (21, 31...), usa-se 'mốt' e não 'một': '21 = hai mươi mốt'."},{"v":"Mốt","p":"Um (1) — em compostos após dezenas","e":"One (1) — in compound numbers after tens","c":"Número","g":"Variante de 'một' usada EXCLUSIVAMENTE na posição de unidade após dezenas: '21 = hai mươi mốt', '31 = ba mươi mốt', '41 = bốn mươi mốt'. NUNCA na posição de dezenas ou centenas. O uso de 'một' em vez de 'mốt' ('hai mươi một') é considerado erro no vietnamita padrão."},{"v":"Mua","p":"Comprar","e":"To buy","c":"Verbo","g":"Verbo de compra. Invariável. Estrutura: S + [sẽ] + mua + [objeto]: 'Tôi sẽ mua một bức tranh mới' (vou comprar um quadro novo). Local de compra com 'ở': 'Tôi mua ở Thái Lan' (comprei na Tailândia). Oposto: 'bán' (vender)."},{"v":"Muốn","p":"Querer","e":"To want","c":"Verbo","g":"Verbo modal que precede outro verbo DIRETAMENTE (sem 'de' ou 'para'): 'Tôi muốn ăn phở' (Quero comer phở — lit. Eu querer comer phở). Estrutura: S + muốn + V + [objeto]. Para desejo de substantivo: 'Tôi muốn một chiếc xe' (quero um carro)."},{"v":"Mười","p":"Dez (10)","e":"Ten (10)","c":"Número","g":"Número cardinal 10. Usado como prefixo para 11-19: 'mười một' (11), 'mười hai' (12), ... 'mười chín' (19). Para 20+, as dezenas usam 'mươi' (não 'mười'): 'hai mươi' (20), 'ba mươi' (30). Distinção entre 'mười' (10 isolado) e 'mươi' (marca de dezena em compostos)."},{"v":"Mươi","p":"Dezena (marcador em compostos: 20, 30, 40...)","e":"Tens marker in compound numbers","c":"Número","g":"Marcador de dezena em compostos de 20 a 90. '20 = hai mươi', '30 = ba mươi', ... '90 = chín mươi'. Diferente de 'mười' (10): aqui o tom é NÃO marcado e é sufixo da dezena. Regras especiais: 21 = 'hai mươi mốt' (não 'một'), 25 = 'hai mươi lăm' (não 'năm'), 24 pode ser 'hai mươi bốn' ou 'hai mươi tư'."},{"v":"Mỹ","p":"EUA (Estados Unidos)","e":"United States (USA)","c":"Nome","g":"Nome dos EUA. Origem histórica: abreviação de 'Mỹ quốc' (País Belo — como os EUA eram chamados por influência chinesa). Gentílico: 'người Mỹ' (americano/ã). Note: no vietnamita moderno, 'người Mỹ' refere-se especificamente a cidadãos dos EUA."},{"v":"Nào","p":"Qual? (sempre ao final da frase)","e":"Which? (always at end)","c":"Interrogativo","g":"Interrogativo para 'qual?'. Como todos os interrogativos vietnamitas, vem no FINAL: 'Bạn là người nước nào?' (De qual país você é? — lit. 'Você é pessoa país qual?'). 'Nào' pode seguir qualquer substantivo: 'cái nào?' (qual deles?), 'ai nào?' (qual pessoa?). Coloca-se no final."},{"v":"Này","p":"Este/Esta (próximo, após substantivo)","e":"This (near, after noun)","c":"Demonstrativo","g":"Demonstrativo para 'este/esta' (próximo ao falante). SEMPRE após o substantivo: 'sách này' (este livro), 'nhà này' (esta casa). NUNCA 'này sách'. Contraste crítico com 'đây': 'sách này đẹp' (este livro é bonito) vs 'Đây là sách' (isso aqui é um livro — đây antes de 'là')."},{"v":"Năm","p":"Cinco (5) — forma base","e":"Five (5) — base form","c":"Número","g":"Número cardinal 5 — forma padrão. Use 'năm' em: '5 = năm', '50 = năm mươi', '500 = năm trăm', '5.000 = năm nghìn'. ATENÇÃO: na posição de UNIDADE após dezenas, usa 'lăm', não 'năm': '15 = mười lăm', '25 = hai mươi lăm'. Regra de ouro: năm para dezenas+, lăm para unidades em compostos."},{"v":"Năm ngoái / Năm nay / Năm sau","p":"Ano passado / Este ano / Ano que vem","e":"Last year / This year / Next year","c":"Expressão","g":"ATENÇÃO: 'ano passado' é NĂM NGOÁI (não 'Năm Trước' — erro comum!). Padrão TRƯỚC/NÀY/SAU: TUẦN TRƯỚC/NÀY/SAU (semana), THÁNG TRƯỚC/NÀY/SAU (mês). Mas para ANO: NĂM NGOÁI (passado), NĂM NAY (este), NĂM SAU (que vem). HAI NĂM SAU = em dois anos."},{"v":"Ngày","p":"Dia / Data","e":"Day / Date","c":"Substantivo","g":"NGÀY = dia ou data. Para dizer datas: NGÀY + número + THÁNG + número + NĂM + número. Ordem: DIA/MÊS/ANO (igual ao Brasil!). 'Hôm nay là ngày bao nhiêu?' = Que dia é hoje? Contraste: NGÀY (dia), HÔM NAY (hoje), HÔM QUA (ontem), NGÀY MAI (amanhã)."},{"v":"Ngày mai","p":"Amanhã","e":"Tomorrow","c":"Expressão","g":"Expressão temporal: 'ngày' (dia) + 'mai' (amanhã/próximo). Posição na frase: geralmente no INÍCIO (ênfase no tempo) ou após o sujeito: 'Ngày mai tôi bận' (Amanhã estou ocupado). Contraste: 'hôm nay' (hoje), 'hôm qua' (ontem), 'ngày mai' (amanhã)."},{"v":"Ngân hàng","p":"Banco","e":"Bank","c":"Substantivo","g":"NGÂN HÀNG = banco (instituição financeira). Frase-exemplo: 'Hôm qua, tôi đã đi ngân hàng' (Ontem, fui ao banco) — combina HÔM QUA com ĐÃ. 'Làm việc ở ngân hàng' = trabalhar no banco. Outras instituições: trường (escola), bệnh viện (hospital), siêu thị (supermercado)."},{"v":"Nghìn","p":"Mil (1.000)","e":"Thousand (1,000)","c":"Número","g":"Número para mil. Nota regional: Norte usa 'nghìn', Sul usa 'ngàn'. Compostos: 'mười nghìn' (10.000), 'một trăm nghìn' (100.000). Zero intermediário: '1.005 = một nghìn linh năm'. Com outros números: '2.500 = hai nghìn năm trăm'."},{"v":"Ngon","p":"Gostoso / Delicioso","e":"Delicious / Tasty","c":"Adjetivo","g":"Adjetivo de sabor. Vem APÓS o sujeito/substantivo: 'phở rất ngon' (phở é muito gostoso). Use 'ngon' APENAS para comida e bebida — para obras (filmes, livros) use 'hay'; para aparência, use 'đẹp'. Exclamações: 'Ngon quá!' / 'Ngon lắm!' — ambas corretas."},{"v":"Ngôi","p":"Classificador (casas e edifícios)","e":"Classifier (houses / buildings)","c":"Classificador","g":"Classificador OBRIGATÓRIO para casas e edifícios ao contar ou referenciar especificamente: 'một ngôi nhà' (uma casa), 'hai ngôi nhà' (duas casas). 'Ngôi nhà kia' = aquela casa (o 'ngôi' especifica que é uma habitação). Também: 'ngôi đình' (templo comunitário), 'ngôi chùa' (pagode)."},{"v":"Ngủ","p":"Dormir","e":"Sleep","c":"Verbo","g":"Verbo 'dormir'. Estrutura com LÚC para perguntar/dizer horário: S + ngủ + LÚC + giờ → 'Tôi ngủ lúc 10 giờ tối' (Durmo às 10 da noite). 'ĐI NGỦ' = ir dormir/deitar: 'Tôi đi ngủ bây giờ' (Vou dormir agora). Componente de PHÒNG NGỦ (quarto de dormir). Oposto: THỨC DẬY (acordar)."},{"v":"Người","p":"Pessoa / Povo","e":"Person / People","c":"Substantivo","g":"Dois usos principais: (1) PESSOA — 'một người' (uma pessoa), 'hai người' (duas pessoas); (2) GENTÍLICO — 'người + país' para indicar nacionalidade: 'người Việt Nam' (vietnamita), 'người Brazil' (brasileiro). Estrutura de identidade nacional: 'Tôi là người [país]'."},{"v":"Nhà","p":"Casa","e":"House / Home","c":"Substantivo","g":"Substantivo para casa, lar. Classificador: 'ngôi' ao contar formalmente: 'một ngôi nhà'. Expressões úteis: 'ở nhà' (em casa), 'về nhà' (voltar para casa), 'nhà mới' (casa nova), 'nhà của tôi' / 'nhà tôi' (minha casa — ambas corretas, 'của' pode ser omitido)."},{"v":"Nước","p":"País / Água","e":"Country / Water","c":"Substantivo","g":"Substantivo com dois significados: (1) PAÍS — 'nước nào?' (qual país?), 'nước tôi' (meu país), 'nước ngoài' (exterior/estrangeiro); (2) ÁGUA — 'uống nước' (beber água), 'nước sôi' (água fervendo). A pergunta de nacionalidade usa o sentido (1): 'người nước nào?' = 'pessoa de qual país?'."},{"v":"Ồ","p":"Oh! (surpresa)","e":"Oh! (surprise)","c":"Interjeição","g":"Interjeição de surpresa (mais forte que 'À'). Usada quando algo surpreende positiva ou negativamente. Geralmente seguida de exclamação: 'Ồ! Tuyệt quá!' (Uau! Que ótimo!). Tom ngã (˜) — deve ser pronunciado com quebra/glotalização no Norte. Equivale a 'Uau!' ou 'Nossa!' em PT."},{"v":"Ông","p":"Avô / O senhor","e":"Grandfather / Sir","c":"Pronome","g":"Pronome social para homem idoso (avô, senhor importante). Muito respeitoso. Uma criança/jovem usa 'cháu' para si mesma e 'ông' para o senhor. Em contextos formais (hotéis, lojas), 'ông' é usado para clientes homens idosos como sinal de respeito máximo."},{"v":"Ở","p":"Estar em / Morar / Em","e":"To be at / To live / At","c":"Verbo","g":"Verbo/preposição versátil: (1) ESTAR EM: 'Tôi ở nhà' (estou em casa); (2) MORAR: 'Tôi ở Hà Nội' (moro em Hanói); (3) PREPOSIÇÃO 'em/at' com compras/eventos: 'Tôi mua ở Thái Lan' (comprei na Tailândia). O contexto determina o sentido. Essencial para expressar localização."},{"v":"Ơi","p":"Ei! / Ó! (partícula de chamado)","e":"Hey! / O! (calling particle)","c":"Partícula","g":"ƠI = partícula de chamado, vem APÓS o nome ou pronome para chamar alguém. Estrutura: NOME + ƠI. Exemplos: 'Minh ơi!' (Ei, Minh!), 'Mẹ ơi!' (Mãe!), 'Anh ơi!' (Ei, irmão!). Tom bằng/ngang (sem tom marcado). Essencial na fala cotidiana — usar apenas o nome sem ƠI pode soar seco ou rude. Equivalente informal ao 'Ó' ou 'Ei' do português. Diferente de ƠI ƠI (expressão de exasperação: 'ai ai!')."},{"v":"Phòng khách","p":"Sala de estar","e":"Living room","c":"Substantivo","g":"Composto: 'phòng' (quarto/sala) + 'khách' (visita). Literalmente 'sala das visitas'. Família de compostos com 'phòng': 'phòng ngủ' (quarto de dormir), 'phòng bếp' (cozinha), 'phòng tắm' (banheiro), 'phòng học' (sala de estudos). 'Phòng' isolado = quarto genérico."},{"v":"Phòng ngủ","p":"Quarto","e":"Bedroom","c":"Substantivo","g":"Composto: 'phòng' (quarto) + 'ngủ' (dormir). Em vietnamita, verbos podem modificar substantivos diretamente sem preposição: 'phòng + ngủ' = 'quarto + dormir' = quarto de dormir. Padrão de apresentação: 'Đây là phòng ngủ, kia là phòng khách' (Isto é o quarto, aquilo é a sala)."},{"v":"Phở","p":"Phở (prato típico vietnamita)","e":"Phở (Vietnamese noodle soup)","c":"Substantivo","g":"Nome do prato mais emblemático do Vietnã — sopa de macarrão (bánh phở) com caldo de carne e ervas. Originário do Norte (Hanói). Sem classificador padrão: 'một tô phở' (uma tigela de phở) ou simplesmente 'ăn phở' (comer phở). Tom hỏi (̉): 'phở' pronunciado com curva descendente-ascendente."},{"v":"Phải không?","p":"Não é? / Certo? (confirmação)","e":"Right? / Isn't it? (tag question)","c":"Expressão","g":"PHẢI KHÔNG? = tag question ao FINAL da frase. Equivale a '...não é?' ou '...certo?'. 'Kia là bức tranh của anh phải không?' = Aquele é seu quadro, não é? Resposta: VÂNG/ĐÚNG (sim, correto) ou KHÔNG (não). Forma mais formal: CÓ PHẢI KHÔNG? (com CÓ no início)."},{"v":"Quá","p":"Demais! / Que...! (exclamação após adjetivo)","e":"So much! / How...! (exclamation after adj.)","c":"Advérbio","g":"Intensificador exclamativo que vem APÓS o adjetivo. Exprime surpresa ou admiração forte: 'đẹp quá!' (lindo demais!), 'ngon quá!' (delicioso demais!). Compare os 3 intensificadores: 'rất + adj' (muito, neutro) / 'adj + quá' (demais!, exclamativo) / 'adj + lắm' (muitíssimo, superlativo enfático)."},{"v":"Quả","p":"Classificador (frutas)","e":"Classifier (fruits)","c":"Classificador","g":"Classificador para frutas e alguns objetos arredondados. OBRIGATÓRIO ao contar: 'một quả táo' (uma maçã), 'hai quả cam' (duas laranjas), 'ba quả chuối' (três bananas), 'một quả bóng' (uma bola). Especificidade: cada tipo de substantivo tem seu classificador; trocar pode soar estranho."},{"v":"Quần áo","p":"Roupa / Roupas","e":"Clothes","c":"Substantivo","g":"Substantivo composto: QUẦN (calça) + ÁO (camisa/blusa) = 'roupas' (termo genérico). Peças específicas: ÁO DÀI (vestido tradicional), QUẦN JEAN (calça jeans), ÁO SƠ MI (camisa social). 'Mua quần áo' = comprar roupas. Adjetivo após: 'quần áo mới' (roupas novas)."},{"v":"Quyển","p":"Classificador (livros)","e":"Classifier (books)","c":"Classificador","g":"Classificador para livros e cadernos (objetos com páginas encadernadas). 'Một quyển sách' (um livro), 'hai quyển sách' (dois livros), 'quyển vở' (um caderno). Alternativa: 'cuốn' é sinônimo mais informal. NÃO use para revistas ('tờ' ou sem classificador específico)."},{"v":"Rất","p":"Muito","e":"Very / Really","c":"Advérbio","g":"Advérbio intensificador. Vem ANTES do adjetivo ou verbo que modifica: 'rất đẹp' (muito bonito), 'rất bận' (muito ocupado), 'rất muốn' (querer muito). POSIÇÃO OPOSTA ao português: em VN = 'muito + adj', não 'adj + muito'. Neutro em tom (não exclamativo como 'quá')."},{"v":"Rộng","p":"Espaçoso / Grande","e":"Spacious / Wide","c":"Adjetivo","g":"Adjetivo de espaço. Refere-se à amplitude, largura ou espaço interno. Usado para casas, quartos, ruas, espaços. Sempre APÓS o substantivo: 'nhà rộng' (casa espaçosa). 'Rộng' e 'đẹp' frequentemente aparecem juntos: 'rất đẹp và rộng' (muito bonito e espaçoso)."},{"v":"Rất vui được gặp","p":"Muito prazer em conhecer","e":"Nice to meet you","c":"Expressão","g":"Expressão de apresentação: RẤT (muito) + VUI (feliz) + ĐƯỢC (ter a oportunidade) + GẶP (encontrar). Lit.: 'muito feliz de ter a oportunidade de encontrar você'. Versão simplificada: 'Vui được gặp bạn'. Resposta: 'Tôi cũng vui!' (Eu também!) ou 'Tôi cũng vậy!'."},{"v":"Sách","p":"Livro","e":"Book","c":"Substantivo","g":"Substantivo para livro. Classificador: 'quyển' (formal) ou 'cuốn' (informal). 'Một quyển sách' = um livro. Adjetivo para avaliar livros: 'hay' (bom/interessante), não 'ngon'. 'Sách này hay quá!' = Que livro bom! Posse: 'sách của tôi' ou 'sách tôi' (meu livro)."},{"v":"Sáu","p":"Seis (6)","e":"Six (6)","c":"Número","g":"Número cardinal 6. Invariável. Compostos: 'mười sáu' (16), 'hai mươi sáu' (26), 'sáu mươi' (60), 'sáu trăm' (600). Sem variantes especiais — 'sáu' é sempre 'sáu' em qualquer posição."},{"v":"Sinh nhật","p":"Aniversário","e":"Birthday","c":"Substantivo","g":"SINH = nascer, NHẬT = dia (sino-vietnamita). Literalmente 'dia do nascimento'. Frase do curso: 'Tuần sau là sinh nhật của mẹ em' (Semana que vem é o aniversário da minha mãe). 'Chúc mừng sinh nhật!' = Feliz aniversário! 'Quà sinh nhật' = presente de aniversário."},{"v":"Sinh viên","p":"Estudante universitário(a)","e":"University student","c":"Profissão","g":"SINH VIÊN = estudante universitário (nível superior). Diferente de HỌC SINH = aluno de ensino fundamental/médio. 'Tôi là sinh viên' (Sou estudante universitário). Sistema de profissões: giáo viên (professor), sinh viên (estudante), bác sĩ (médico)."},{"v":"Sau","p":"Depois / Atrás / Próximo (tempo)","e":"After / Behind / Next (time)","c":"Expressão","g":"SAU = depois/atrás (oposto de TRƯỚC). Usos: (1) TEMPO — vem após o substantivo temporal: 'tuần sau' (semana que vem), 'tháng sau' (mês que vem), 'năm sau' (ano que vem), 'sau đó' (depois disso); (2) ESPAÇO — atrás: 'ở sau nhà' (atrás da casa). SAU KHI = depois que (conjunção temporal)."},{"v":"Sẽ","p":"Vai / Irá (futuro — antes do verbo)","e":"Will (future marker — before verb)","c":"Partícula","g":"Marcador de tempo FUTURO. Posição: ANTES do verbo principal: 'Tôi sẽ đến' (Eu vou vir), 'Tôi sẽ mua...' (Vou comprar). O verbo NUNCA muda. Sem 'sẽ', a frase é ambígua quanto ao tempo. SISTEMA DE MARCADORES: 'đã' (passado), [nada] (presente), 'đang' (contínuo), 'sẽ' (futuro)."},{"v":"Tám","p":"Oito (8)","e":"Eight (8)","c":"Número","g":"Número cardinal 8. Invariável. Compostos: 'mười tám' (18), 'hai mươi tám' (28), 'tám mươi' (80), 'tám trăm' (800), 'linh tám' (zero-oito, em compostos). Sem variantes especiais."},{"v":"Táo","p":"Maçã","e":"Apple","c":"Substantivo","g":"Substantivo para maçã. Classificador: 'quả' (para frutas). 'Một quả táo' = uma maçã. Tipos: 'táo xanh' (maçã verde — lit. verde), 'táo đỏ' (maçã vermelha). Note: 'táo' também é um nome masculino vietnamita. Frases compostas: 'nước táo' = suco de maçã."},{"v":"Tặng","p":"Presentear / Dar de presente","e":"Give as a gift","c":"Verbo","g":"TẶNG = presentear (ato de dar). Estrutura: TẶNG + pessoa + coisa: 'Tặng mẹ quần áo' = presentear a mãe com roupa. QUÀ = presente (substantivo). TẶNG QUÀ = dar um presente. TẶNG QUÀ SINH NHẬT = dar presente de aniversário. Diferente de CHO (dar/entregar sem contexto de presente)."},{"v":"Tên","p":"Nome","e":"Name","c":"Substantivo","g":"Substantivo para nome. Pergunta padrão de apresentação: 'Bạn tên là gì?' (Qual é o seu nome? — lit. 'Você nome é o quê?'). Resposta: 'Tôi tên là [nome]' ou simplesmente 'Tôi là [nome]'. 'Tên là' é combinação fixa. Compare: 'họ' (sobrenome), 'tên' (primeiro nome)."},{"v":"Thái Lan","p":"Tailândia","e":"Thailand","c":"Nome","g":"Nome do país Tailândia. Gentílico: 'người Thái Lan' (tailandês/a). Precedido por 'ở' ao indicar local: 'Tôi mua ở Thái Lan' (comprei na Tailândia). A preposição 'ở' antes de nome de país indica localização/origem da ação."},{"v":"Tháng","p":"Mês","e":"Month","c":"Substantivo","g":"THÁNG + número = mês. THÁNG MỘT (jan), THÁNG HAI (fev)... THÁNG MƯỜI HAI (dez). Exceção: THÁNG TƯ = abril (usa TƯ = 4). Padrão temporal: THÁNG TRƯỚC (mês passado), THÁNG NÀY (este mês), THÁNG SAU (mês que vem). 'Tháng mấy?' = Que mês?"},{"v":"Thứ Hai / Thứ Ba / Thứ Tư","p":"Segunda / Terça / Quarta","e":"Monday / Tuesday / Wednesday","c":"Expressão","g":"Dias da semana: THỨ + número (conta a partir de 2). THỨ HAI (seg=2), THỨ BA (ter=3), THỨ TƯ (qua=4). ATENÇÃO: THỨ TƯ usa TƯ (variante de 4 em compostos). Sistema mnemônico: segunda=dia 2, terça=dia 3... sábado=dia 7. DOMINGO = CHỦ NHẬT (único que não segue o padrão)."},{"v":"Thứ Năm / Thứ Sáu / Thứ Bảy","p":"Quinta / Sexta / Sábado","e":"Thursday / Friday / Saturday","c":"Expressão","g":"THỨ NĂM (qui=5), THỨ SÁU (sex=6), THỨ BẢY (sáb=7). Sistema perfeito: THỨ + número de 2 a 7. ATENÇÃO: para 'quinta' usa NĂM (não LĂM — LĂM só em compostos após dezenas). Para perguntar o dia: 'Hôm nay là thứ mấy?' (Que dia da semana é hoje?)."},{"v":"Thức dậy","p":"Acordar / Despertar","e":"Wake up","c":"Verbo","g":"Composto verbal: THỨC (estar acordado/em vigília) + DẬY (levantar). 'Anh thức dậy lúc mấy giờ?' = A que horas você acorda? Par com NGỦ (dormir): 'Tôi ngủ lúc 10 giờ và thức dậy lúc 6 giờ sáng.' THỨC isolado = ficar acordado: 'Tôi thức đến 2 giờ sáng' (Fiquei acordado até 2 da manhã). DẬY isolado = levantar-se da cama."},{"v":"Tôi","p":"Eu (neutro / mesma idade)","e":"I / Me (neutral)","c":"Pronome","g":"Pronome 'eu/me' mais seguro para iniciantes — neutro, sem implicação de idade. Usado com pessoas da mesma faixa etária. Em interações com pessoas mais velhas, troque 'tôi' por 'em' (falando com irmão mais velho) ou 'cháu' (falando com avós/tios). 'Tôi' é sempre correto até você aprender os outros."},{"v":"Trăm","p":"Cem (100)","e":"Hundred (100)","c":"Número","g":"Número para cem. Compostos: 'một trăm' (100), 'hai trăm' (200), 'năm trăm' (500). REGRA ESPECIAL: quando o dígito das dezenas é zero, use 'linh': '101 = một trăm linh một'. Se não é zero: '156 = một trăm năm mươi sáu'. Sem zero intermediário, sem 'linh'."},{"v":"Triệu","p":"Milhão (1.000.000)","e":"Million (1,000,000)","c":"Número","g":"Número para um milhão. Hierarquia numérica completa: tỷ (bilhão, 10⁹) > triệu (milhão, 10⁶) > nghìn (mil, 10³) > trăm (cem, 10²) > mươi (dez) > [unidade]. 'Hai triệu' = 2 milhões. Importante em contexto econômico (moeda: 'triệu đồng')."},{"v":"Trung Quốc","p":"China","e":"China","c":"Nome","g":"Nome da China (República Popular). Origem sino-vietnamita: 'Trung' (central) + 'Quốc' (nação). Gentílico: 'người Trung Quốc'. Outros países asiáticos: 'Nhật Bản' (Japão), 'Hàn Quốc' (Coreia do Sul), 'Triều Tiên' (Coreia do Norte)."},{"v":"Trường đại học","p":"Universidade","e":"University","c":"Substantivo","g":"TRƯỜNG = escola (genérico). TRƯỜNG ĐẠI HỌC = universidade (lit. 'escola de estudo superior'). Níveis: TRƯỜNG MẦM NON (pré-escola), TRƯỜNG TIỂU HỌC (fundamental), TRƯỜNG TRUNG HỌC (médio), TRƯỜNG ĐẠI HỌC (universidade). ĐẠI HỌC QUỐC GIA = Universidade Nacional."},{"v":"Tuần","p":"Semana","e":"Week","c":"Substantivo","g":"TUẦN = semana. Padrão temporal: TUẦN TRƯỚC (semana passada), TUẦN NÀY (esta semana), TUẦN SAU (semana que vem). HAI TUẦN SAU = em duas semanas. Paralelismo: THÁNG (mês), TUẦN (semana). ATENÇÃO para ANO: NĂM NGOÁI ✓, NĂM TRƯỚC ✗ (ver Năm ngoái/nay/sau)."},{"v":"Tuần trước / Tuần sau / Tuần này","p":"Semana passada / Semana que vem / Esta semana","e":"Last week / This week / Next week","c":"Expressão","g":"Sistema temporal de SEMANAS: TUẦN TRƯỚC (semana passada) → usa ĐÃ | TUẦN NÀY (esta semana) → depende do contexto | TUẦN SAU (semana que vem) → usa SẼ. Mesmo padrão para meses: THÁNG TRƯỚC / THÁNG NÀY / THÁNG SAU. ATENÇÃO: para ANO a exceção é NĂM NGOÁI (não TUẦN TRƯỚC). HAI TUẦN TRƯỚC = há duas semanas. HAI TUẦN SAU = em duas semanas."},{"v":"Tuổi","p":"Idade / Anos de idade","e":"Age / Years old","c":"Substantivo","g":"Estrutura para idade: Pronome + [número] + TUỔI. SEM VERBO — não se diz 'Tôi LÀ 30 tuổi'. 'Anh bao nhiêu tuổi?' (adulto) vs 'Cháu mấy tuổi?' (criança). Exemplos: 'Tôi 25 tuổi' (Tenho 25 anos), 'Cháu 7 tuổi' (A criança tem 7 anos). TUỔI tem tom hỏi."},{"v":"Tuyệt","p":"Ótimo / Fantástico","e":"Great / Fantastic","c":"Adjetivo","g":"Adjetivo/interjeição para 'ótimo, fantástico, incrível'. SEMPRE em contexto positivo. Como exclamação: 'Tuyệt quá!' (Que ótimo!), 'Thật tuyệt!' (Que fantástico mesmo!). Como descrição: 'Rất tuyệt' (muito ótimo). Mais forte que 'tốt' (bom) — tuyệt expressa entusiasmo."},{"v":"Trước","p":"Antes / Na frente / Passado (tempo)","e":"Before / In front of / Previous (time)","c":"Expressão","g":"TRƯỚC = antes/na frente (oposto de SAU). Usos: (1) TEMPO — vem após o substantivo temporal: 'tuần trước' (semana passada), 'tháng trước' (mês passado); ATENÇÃO: para ANO PASSADO use NĂM NGOÁI, não 'năm trước'! (2) ESPAÇO — na frente: 'ở trước nhà' (na frente da casa); (3) TRƯỚC KHI = antes de (conjunção): 'Trước khi đi, anh gọi tôi.' (Antes de ir, me ligue)."},{"v":"Tư","p":"Quatro (4) — alternativa em compostos","e":"Four (4) — alternative in compound numbers","c":"Número","g":"Variante de 'bốn' (4) usada NA POSIÇÃO DE UNIDADE após dezenas: '24 = hai mươi tư', '34 = ba mươi tư'. ATENÇÃO: para a dezena 40, mantém-se 'bốn': '40 = bốn mươi' (NUNCA 'tư mươi'). 'Tư' só aparece como unidade em 24, 34, 44, etc."},{"v":"Tỷ","p":"Bilhão (1.000.000.000)","e":"Billion (1,000,000,000)","c":"Número","g":"Número para 1 bilhão (10⁹). O maior marcador numérico do uso cotidiano vietnamita. Muito comum em reportagens econômicas: 'nghìn tỷ' (trilhão, lit. mil bilhões). 'Một tỷ đồng' = um bilhão de dong. Note: 'tỷ' tem tom hỏi — deve ser pronunciado com inflexão curva."},{"v":"Và","p":"E (conecta adjetivos ou substantivos)","e":"And (connects adjectives or nouns)","c":"Conjunção","g":"Conjunção 'e'. Conecta adjetivos: 'đẹp và rộng' (bonito e espaçoso). Pode conectar substantivos: 'sách và bút' (livro e caneta). Para VERBOS, o vietnamita geralmente os coloca em sequência SEM conjunção: 'Tôi ăn uống' (como e bebo — lit. 'eu como bebo'). 'Và' raro entre verbos."},{"v":"Vâng","p":"Sim (forma formal e respeitosa)","e":"Yes (formal and respectful)","c":"Confirmação","g":"Confirmação afirmativa FORMAL e respeitosa. Use com pessoas mais velhas, superiores hierárquicos ou em situações formais. Informal/igual: 'ừ' ou 'có'. Sistema: 'vâng' (muito respeitoso) > 'dạ/có' (respeitoso) > 'ừ' (casual, igual ou inferior em hierarquia)."},{"v":"Vợ","p":"Esposa","e":"Wife","c":"Substantivo","g":"VỢ = esposa. CHỒNG = marido. Apresentação: 'Kia là vợ của tôi' (Aquela é minha esposa). Posse: 'vợ của anh ấy' (a esposa dele). No casal vietnamita, a esposa chama o marido de 'anh' e ele a chama de 'em' — pronomes baseados em hierarquia de idade real ou simbólica."},{"v":"Việt Nam","p":"Vietnã","e":"Vietnam","c":"Nome","g":"Nome do país. Origem: 'Việt' (povo Viet) + 'Nam' (sul). Idioma: 'tiếng Việt'. Regiões: 'miền Bắc' (Norte), 'miền Trung' (Centro), 'miền Nam' (Sul). Dialetos principais diferem em pronúncia e vocabulário. Você está estudando o dialeto do Norte (Hanói)."},{"v":"Vui","p":"Feliz / Alegre","e":"Happy / Joyful","c":"Adjetivo","g":"Adjetivo de estado emocional. Vem após o sujeito: 'Tôi rất vui' (estou muito feliz). 'Vui quá!' (Que alegria!). Expressão importante: 'Vui lòng' = por favor (lit. 'coração alegre' — pedido formal). Compare: 'hạnh phúc' (feliz/satisfeito, mais profundo que 'vui')."},{"v":"Xin chào","p":"Olá (forma formal)","e":"Hello (formal)","c":"Saudação","g":"'Xin' (gentilmente pedir/por favor) + 'chào' (saudar). Versão formal e completa de 'chào'. Pode ser usada com qualquer pessoa em qualquer situação. Em apresentações: 'Xin chào, tôi là [nome]'. 'Xin' + verbo = polidez: 'Xin lỗi' (desculpe-me — lit. 'peço perdão')."},{"v":"Xin lỗi","p":"Desculpe / Com licença","e":"Sorry / Excuse me","c":"Expressão","g":"XIN (por favor/peço) + LỖI (erro/falta) = 'peço desculpas'. Dois usos: (1) DESCULPE — por erros: 'Xin lỗi, tôi đến muộn' (Desculpe, cheguei tarde); (2) COM LICENÇA — antes de interromper: 'Xin lỗi, anh tên là gì?' (Com licença, como é seu nome?). XIN = partícula de polidez."},{"v":"Khi nào / Bao giờ / Lúc nào?","p":"Quando? (interrogativos de tempo)","e":"When? (time interrogatives)","c":"Interrogativo","g":"Três formas de perguntar 'quando?': (1) KHI NÀO — geral; (2) BAO GIỜ — com ideia de futuro ou passado (mais comum); (3) LÚC NÀO — em que momento exato. Podem ir no INÍCIO ou FINAL da frase: 'Bao giờ anh sẽ đi?' = 'Anh sẽ đi bao giờ?' (Quando você vai?). KHI NÀO e BAO GIỜ são intercambiáveis na maioria dos contextos."},{"v":"Gia đình","p":"Família","e":"Family","c":"Substantivo","g":"GIA ĐÌNH = família. Estrutura para dizer o tamanho: GIA ĐÌNH + posse + CÓ + número + NGƯỜI. 'Gia đình tôi có 4 người: bố, mẹ, anh trai và tôi.' Para perguntar: 'Gia đình bạn có mấy người?' (Quantas pessoas tem sua família?). GIA = casa/família, ĐÌNH = sala principal (sino-vietnamita)."},{"v":"Nấu ăn","p":"Cozinhar","e":"Cook","c":"Verbo","g":"NẤU = cozinhar (preparar no fogo). ĂN = comer. NẤU ĂN = cozinhar comida. Frase do curso: 'Hôm nay mẹ em nấu ăn' (Hoje minha mãe cozinha). Compostos comuns: NẤU CƠM (cozinhar arroz), NẤU PHỞ (preparar phở). Pergunta: 'Ai nấu ăn hôm nay?' (Quem cozinha hoje?)."},{"v":"Anh trai","p":"Irmão mais velho","e":"Older brother","c":"Substantivo","g":"Sistema de irmãos: ANH TRAI (irmão mais velho) | CHỊ GÁI (irmã mais velha) | EM TRAI (irmão mais novo) | EM GÁI (irmã mais nova). ANH/CHỊ/EM sozinhos também funcionam como pronomes sociais. Frase do PDF: 'Gia đình tôi có bố, mẹ, anh trai và tôi.' (Minha família tem pai, mãe, irmão mais velho e eu.)"},{"v":"Họ","p":"Eles / Elas","e":"They / Them","c":"Pronome","g":"HỌ = eles/elas (3ª pessoa do plural, neutro). Sistema de 3ª pessoa: ANH ẤY (ele, mais velho); CHỊ ẤY (ela, mais velha); EM ẤY (ele/ela mais novo/a); HỌ (eles/elas — grupo). HỌ também significa 'sobrenome' em outro contexto. Frase do curso: 'Họ đều rất bận.' (Eles todos estão muito ocupados.)"},{"v":"Đều","p":"Ambos / Todos (sem exceção)","e":"Both / All (without exception)","c":"Advérbio","g":"ĐỀU = 'ambos' / 'todos' — indica que CADA MEMBRO do grupo faz a mesma ação. Posição: antes do verbo. Exemplos: 'Bố mẹ tôi đều đi làm' (meus pais ambos trabalham); 'Chúng tôi đều là sinh viên' (somos todos estudantes). Compare com CŨNG: 'cũng' acrescenta 'também' ao anterior; 'đều' distribui sobre todo o grupo."},{"v":"Cũng / Cũng vậy","p":"Também / Eu também","e":"Also / Me too / Same here","c":"Advérbio","g":"CŨNG = 'também' (antes do verbo): S + CŨNG + V. CŨNG VẬY = 'eu também' / 'igualmente' (frase resposta, sem repetir o verbo). Exemplos: 'Tôi cũng vui!' (Eu também estou feliz!); 'Anh Minh là người Việt Nam. Tôi cũng vậy.' (O Minh é vietnamita. Eu também.). 'Rất vui được gặp!' → 'Tôi cũng vậy!'."},{"v":"Đã...chưa? / Rồi / Chưa","p":"Já...? (pergunta) / Já / Ainda não","e":"Have...yet? / Already / Not yet","c":"Partícula","g":"Sistema de 3 peças: PERGUNTA: S + ĐÃ + V + CHƯA? (Você já...?) | RESPOSTA SIM: S + V + RỒI (já fiz — RỒI ao FINAL) | RESPOSTA NÃO: S + CHƯA + V (ainda não fiz — CHƯA ANTES do verbo). Exemplos: 'Anh đã ăn chưa?' → 'Tôi ăn rồi.' / 'Tôi chưa ăn.' Diferente de ĐÃ...KHÔNG? (pergunta sim/não simples sem ideia de 'ainda')."},{"v":"Chị gái","p":"Irmã mais velha","e":"Older sister","c":"Substantivo","g":"CHỊ GÁI = irmã mais velha (mulher). Compare: ANH TRAI (irmão mais velho, homem). Como pronome social, CHỊ sozinha já significa 'irmã mais velha / você (mulher mais velha)'. Com TRAI/GÁI se qualifica o gênero: ANH TRAI / CHỊ GÁI. Árvore da família: Ông/Bà → Bố/Mẹ → Chị gái | Anh trai | (Tôi) | Em trai | Em gái."},{"v":"Em trai","p":"Irmão mais novo","e":"Younger brother","c":"Substantivo","g":"EM TRAI = irmão mais novo (homem). EM = mais novo do que você; TRAI = masculino. Compare: EM GÁI (irmã mais nova, mulher). Como pronome, EM sozinho = 'eu' ao falar com pessoas mais velhas, ou 'irmão/irmã mais novos' no geral. Para especificar gênero: EM TRAI (jovem masculino) / EM GÁI (jovem feminino)."},{"v":"Em gái","p":"Irmã mais nova","e":"Younger sister","c":"Substantivo","g":"EM GÁI = irmã mais nova (mulher). Resumo completo dos irmãos: ANH TRAI (irmão mais velho) | CHỊ GÁI (irmã mais velha) | EM TRAI (irmão mais novo) | EM GÁI (irmã mais nova). Atenção: ANH e CHỊ também são pronomes para quem é mais velho que você; EM é pronome para quem é mais novo. Os compostos com TRAI/GÁI especificam o gênero."},{"v":"Anh rể","p":"Cunhado (marido da chị gái)","e":"Brother-in-law (older sister's husband)","c":"Substantivo","g":"ANH RỂ = cunhado que é mais velho que você — especificamente o marido da sua irmã mais velha (chị gái). Família por afinidade: ANH RỂ (cunhado sênior) | CHỊ DÂU (cunhada sênior — esposa do anh trai) | EM RỂ (cunhado júnior) | EM DÂU (cunhada júnior). Diferente de tiếng Anh onde 'brother-in-law' cobre tudo."},{"v":"Chị dâu","p":"Cunhada (esposa do anh trai)","e":"Sister-in-law (older brother's wife)","c":"Substantivo","g":"CHỊ DÂU = cunhada que é mais velha que você — especificamente a esposa do seu irmão mais velho (anh trai). DÂU também significa 'nora' (con dâu = daughter-in-law). O sistema de in-laws usa os pronomes sociais de idade: CHỊ (mais velha) ou EM (mais nova) + DÂU/RỂ."},{"v":"Em rể","p":"Cunhado (marido da em gái)","e":"Brother-in-law (younger sister's husband)","c":"Substantivo","g":"EM RỂ = cunhado mais novo que você — especificamente o marido da sua irmã mais nova (em gái). RỂ (rể) = gênero — marido que entrou na família. Compare ANH RỂ (cunhado mais velho) vs EM RỂ (cunhado mais novo). O prefixo ANH/CHỊ/EM reflete a posição de idade relativa ao falante."},{"v":"Em dâu","p":"Cunhada (esposa do em trai)","e":"Sister-in-law (younger brother's wife)","c":"Substantivo","g":"EM DÂU = cunhada mais nova que você — especificamente a esposa do seu irmão mais novo (em trai). DÂU = lado feminino de um casamento que entra na família. CON DÂU = nora (filho que casou). EM DÂU = cunhada júnior. CHỊ DÂU = cunhada sênior. A distinção ANH/CHỊ/EM nos títulos de in-laws indica sempre quem é mais velho em relação ao falante."},{"v":"Hẹn gặp lại","p":"Até logo / Até a próxima","e":"See you again / Goodbye","c":"Saudação","g":"HẸN = combinar / marcar encontro. GẶP = encontrar. LẠI = de novo. HẸN GẶP LẠI = 'até a próxima' (literalmente 'combinado de se encontrar de novo'). Aparece na conversa do Bây Giờ PDF: 'Chào em! Hẹn gặp lại.' Formas de despedida: CHÀO (tchau informal), HẸN GẶP LẠI (até a próxima), TẠM BIỆT (adeus mais formal)."},{"v":"Giờ","p":"Hora / O'clock","e":"Hour / O'clock","c":"Substantivo","g":"GIỜ = hora (unidade de tempo e para dizer horas no relógio). Formato: NÚMERO + GIỜ (+ PHÚT). '9 giờ' = 9 horas / 9 em ponto. Para perguntar: 'Bây giờ là mấy giờ?' (Que horas são?) / 'Mấy giờ rồi?' (forma casual). GIỜ também aparece em 'giờ học' (hora de aula) e 'giờ làm việc' (hora de trabalho)."},{"v":"Phút","p":"Minuto","e":"Minute","c":"Substantivo","g":"PHÚT = minuto. Formato completo: [hora] GIỜ [minutos] PHÚT. Exemplos: 8:15 = 'tám giờ mười lăm phút'; 10:45 = 'mười một giờ kém mười lăm phút'. PHÚT pode ser omitido na fala casual. Compare: GIỜ (hora), PHÚT (minuto), GIÂY (segundo)."},{"v":"Rưỡi","p":"E meia (:30)","e":"Half past (:30)","c":"Expressão","g":"RƯỠI = 'e meia' (exatamente :30). Atalho: '8 giờ rưỡi' = '8 giờ 30 phút'. RƯỠI vem sempre após GIỜ. Só se usa para :30 exato — outros minutos precisam de PHÚT. Não existe '8 giờ rưỡi 5' (incorreto). Dica: RƯỠI de RƯỠI significa 'metade'."},{"v":"Kém","p":"Menos / Faltam ... minutos","e":"Less / Minutes to (the hour)","c":"Expressão","g":"KÉM = 'menos' / 'faltam'. Usado para horários entre :31 e :59. Estrutura: [PRÓXIMA HORA] GIỜ KÉM [minutos faltando] PHÚT. Exemplos: 8:40 = '9 giờ kém 20 phút' (faltam 20 para as 9); 6:50 = '7 giờ kém 10 phút'. Lógica: olha para a PRÓXIMA hora, não para a atual."},{"v":"Buổi sáng / trưa / chiều / tối / đêm","p":"Manhã / Meio-dia / Tarde / Noite / Madrugada","e":"Morning / Noon / Afternoon / Evening / Late night","c":"Expressão","g":"Sistema de 12 horas com período do dia: SÁNG (manhã: 1h–10h), TRƯA (ao meio-dia: 11h–12h), CHIỀU (tarde: 13h–18h), TỐI (noite: 19h–22h), ĐÊM (madrugada: após 22h). Uso: hora + período: '9 giờ sáng' (9 da manhã), '3 giờ chiều' (3 da tarde). BUỔI pode anteceder qualquer um: 'buổi sáng' = 'de manhã' sem hora específica."},{"v":"Lúc","p":"Às (horário) / Na hora de","e":"At (a time)","c":"Preposição","g":"LÚC = 'às' (para indicar o horário de uma ação). Estrutura: S + V + LÚC + horário. Para perguntar: 'S + V + LÚC MẤY GIỜ?' = 'A que horas vai [fazer]?'. Exemplos: 'Anh ngủ lúc mấy giờ?' (A que horas você dorme?) / 'Tôi ngủ lúc 10 giờ tối.' (Durmo às 10 da noite.) Diferença com KHI: LÚC indica momento específico, KHI é mais geral."},{"v":"Lớp học","p":"Aula / Sala de aula / Turma","e":"Class / Classroom","c":"Substantivo","g":"LỚP = turma/classe/andar. HỌC = estudar. LỚP HỌC = aula ou sala de aula. Outros compostos: GIỜ HỌC (hora de aula), BÀI HỌC (lição), PHÒNG HỌC (sala de aula — o espaço físico). Para perguntar horário: 'Mấy giờ lớp học sẽ kết thúc?' = 'A que horas a aula vai terminar?'"},{"v":"Kết thúc","p":"Terminar / Acabar / Finalizar","e":"End / Finish","c":"Verbo","g":"KẾT THÚC = terminar, acabar, finalizar (ação chega ao fim). Frase do curso: 'Lớp học kết thúc lúc 5 giờ chiều.' (A aula termina às 5 da tarde.) Sinônimo mais informal: XONG (acabar/terminar uma tarefa). Para perguntar: 'Mấy giờ kết thúc?' = 'A que horas termina?'"},{"v":"Về nhà","p":"Ir para casa / Voltar para casa","e":"Go home / Return home","c":"Verbo","g":"VỀ = voltar/retornar. VỀ NHÀ = ir/voltar para casa. VỀ NHÀ SỚM = chegar em casa cedo. Frase do curso: 'Em về nhà lúc 4 giờ chiều.' (Vou para casa às 4 da tarde.) Não se usa 'đi nhà' para ir para casa em vietnamita — sempre use VỀ NHÀ. Compare: ĐI (ir, destino genérico) vs VỀ (retornar ao ponto de origem)."},{"v":"Phải + V","p":"Ter que / Precisar (obrigação)","e":"Have to / Must (obligation)","c":"Modal","g":"PHẢI + VERBO = 'ter que' / 'ser obrigado a'. Estrutura: S + PHẢI + verbo + complemento. Exemplos: 'Tôi phải đi học' (Tenho que ir estudar), 'Anh phải làm việc hôm nay' (Você tem que trabalhar hoje). ATENÇÃO: PHẢI KHÔNG? (tag question 'não é?') é uso totalmente diferente — PHẢI aqui é verbo modal de obrigação necessidade."},{"v":"Đón","p":"Buscar / Pegar (alguém)","e":"Pick up (someone)","c":"Verbo","g":"ĐÓN = buscar / ir pegar alguém em algum lugar. ĐÓN CON = buscar filho(a) (na escola etc.); ĐÓN KHÁCH = receber/buscar um hóspede. Frase real do curso: 'Em phải đón con.' (Tenho que buscar meu filho.) Diferente de NHẬN (receber algo físico) — ĐÓN é para pessoas."},{"v":"Khoảng","p":"Por volta de / Aproximadamente","e":"Around / Approximately","c":"Advérbio","g":"KHOẢNG = 'por volta de' / 'aproximadamente'. Vem antes de números (horas, idades, quantidades). Exemplos: 'Khoảng 5 giờ chiều' (por volta das 5 da tarde); 'khoảng 30 tuổi' (por volta de 30 anos); 'khoảng 10 phút' (cerca de 10 minutos). Para horários aproximados: 'Khoảng mấy giờ?' = 'Por volta de que horas?'"},{"v":"Nền nhà","p":"Chão / Piso","e":"Floor","c":"Substantivo","g":"NỀN NHÀ = chão / piso (superfície de uma casa). NỀN = base/fundação, NHÀ = casa. Aparece no PDF de Pronúncia como exemplo da terminação '-ên'. Compostos com NỀN: 'nền đất' (chão de terra), 'nền gạch' (piso de cerâmica). Adjetivos comuns para descrever o chão: ĐẸP (bonito), RỘNG (espaçoso), SẠCH (limpo). Área da casa: NỀN NHÀ (chão), TƯỜNG (parede), TRẦN NHÀ (teto)."},{"v":"Đếm","p":"Contar (números)","e":"To count","c":"Verbo","g":"ĐẾM = contar (ação de enumerar). Aparece no PDF de Pronúncia junto a ĐẾN (chegar) — sons parecidos, tons diferentes. ĐẾN (tom sắc, alto-crescente) vs ĐẾM (tom huyền, descendente). Estrutura: S + đếm + [objeto]: 'Đếm từ 1 đến 10' (Contar de 1 a 10). Contextos: 'Đếm tiền' (contar dinheiro), 'Đếm người' (contar pessoas). Não confundir com ĐỌC (ler) nem TÍNH (calcular)."},{"v":"Đi làm","p":"Ir trabalhar","e":"Go to work","c":"Verbo","g":"ĐI LÀM = ir trabalhar (foco no ato de sair para o trabalho). ĐI = ir + LÀM = fazer/trabalhar. Frase do PDF Família: 'Bố mẹ tôi đều đi làm' (Meus pais ambos vão trabalhar). Compare: LÀM VIỆC (trabalhar — foco na atividade em si) vs ĐI LÀM (ir ao trabalho — foco no deslocamento). Perguntas: 'Anh có đi làm không?' (Você vai trabalhar?) / 'Mấy giờ anh đi làm?' (A que horas você vai trabalhar?)."},{"v":"Đi học","p":"Ir estudar / Ir à escola","e":"Go to school/study","c":"Verbo","g":"ĐI HỌC = ir estudar / ir à escola (foco no deslocamento até o local de estudo). ĐI = ir + HỌC = estudar. Frase do PDF Horas: 'Tôi phải đi học' (Tenho que ir estudar). Compare: HỌC (estudar em geral) vs ĐI HỌC (ir ao local de estudo). Série de ĐI + destino/atividade: ĐI LÀM (ir trabalhar), ĐI HỌC (ir estudar), ĐI CHỢ (ir ao mercado), ĐI NGỦ (ir dormir). Perguntas: 'Khi nào em đi học?' (Quando você vai à escola?)"},{"v":"Ngồi","p":"Sentar / Sentar-se","e":"To sit / Sit down","c":"Verbo","g":"NGỒI = sentar / estar sentado. Verbo essencial de postura. Frase do PDF Casa: 'Mời anh ngồi!' (Por favor, sente-se! — lit. convido você a sentar). 'Mời + pronome + ngồi' = expressão de hospitalidade para convidar alguém a se sentar. Compare posturas: NGỒI (sentado), ĐỨNG (em pé), NẰM (deitado). 'Ngồi xuống' (sentar-se agora — xuống = para baixo)."},{"v":"Trường","p":"Escola (em geral)","e":"School (general)","c":"Substantivo","g":"TRƯỜNG = escola ou instituição de ensino (termo genérico). O PDF de Idade e Trabalho ensina: 'Trường: School (In general)' vs 'Trường đại học: University'. Tipos: TRƯỜNG MẦM NON (pré-escola), TRƯỜNG TIỂU HỌC (fundamental), TRƯỜNG TRUNG HỌC (médio), TRƯỜNG ĐẠI HỌC (universidade). Uso: 'Đi học ở trường nào?' (Em qual escola você estuda?). Compare: TRƯỜNG (escola física) vs LỚP HỌC (a aula/turma)."},{"v":"Ấy","p":"Ele / Ela (contexto anterior)","e":"He / She (contextual 3rd person)","c":"Pronome","g":"ẤY = pronome de 3ª pessoa APÓS um pronome social — indica que se fala SOBRE a pessoa, não COM ela. Sistema: ANH ẤY (ele, homem mais velho), CHỊ ẤY (ela, mulher mais velha), EM ẤY (ele/ela mais novo/a), CÔ ẤY (ela, professora/tia), CHỒNG CỦA CÔ ẤY (o marido dela). Frase do PDF Casa: 'Cô ấy rất đẹp.' (Ela é muito bonita.). ẤY NUNCA abre a frase — sempre depois do pronome social. Diferente: ĐÓ (aquele, demonstrativo) vs ẤY (ele/ela como sujeito de referência)."},{"v":"Ô tô","p":"Carro","e":"Car","c":"Substantivo","g":"Ô TÔ = carro (automóvel). Palavra de origem francesa (auto). Classificador: 'chiếc' ou 'cái': 'một chiếc ô tô' (um carro). Compostos: 'xe ô tô' (veículo carro). Outros transportes: XE MÁY (moto), XE BUS / XE BUÝT (ônibus), TÀU (trem/navio). Adjetivos comuns: 'ô tô mới' (carro novo), 'ô tô cũ' (carro usado)."},{"v":"Cá","p":"Peixe","e":"Fish","c":"Substantivo","g":"CÁ = peixe (em geral). Classificador: CON (para animais). 'Một con cá' = um peixe. Compostos culinários: CÁ KHO (peixe cozido no molho), CÁ CHIÊN (peixe frito), CÁ HẤP (peixe no vapor). Compare PHỞ GÀ (phở de frango) vs PHỞ BÒ (phở de carne) — CÁ é opção alternativa em sopas. Sistema com CON: con cá (peixe), con gà (galinha), con mèo (gato), con chó (cachorro)."},{"v":"Gà","p":"Galinha / Frango","e":"Chicken","c":"Substantivo","g":"GÀ = galinha (o animal) / frango (a carne). Classificador: CON (animais): 'một con gà' (uma galinha). Distinção: CON GÀ (animal vivo) vs THỊT GÀ (carne de frango). Prato famoso: PHỞ GÀ (phở de frango) vs PHỞ BÒ (phở de carne bovina). Tom huyền (hà): GÀ pronunciado com tom descendente suave. Compare outros animais: con mèo (gato), con chó (cachorro), con cá (peixe)."},{"v":"Tai","p":"Orelha","e":"Ear","c":"Substantivo","g":"TAI = orelha. Aparece nos exercícios de pronúncia como exemplo da terminação '-ai'. Partes do corpo básicas: TAI (orelha), MẮT (olho), MŨI (nariz), MIỆNG (boca), ĐẦU (cabeça), TAY (mão/braço), CHÂN (perna/pé). Classificador: 'cái' ou sem classificador para partes do corpo em frases do cotidiano. 'Đau tai' = dor de ouvido."},{"v":"Học","p":"Estudar / Aprender","e":"To study / To learn","c":"Verbo","g":"HỌC = estudar ou aprender. Fundamental para o cotidiano: ĐI HỌC (ir à escola/estudar), HỌC TIẾNG VIỆT (estudar vietnamita), SẼ HỌC LÚC MẤY GIỜ? (a que horas vai estudar?). Estrutura: S + HỌC + matéria: 'Tôi học tiếng Anh' (Estudo inglês). Par oposto: DẠY (ensinar) vs HỌC (aprender). Compostos: LỚP HỌC (aula/turma), HỌC SINH (aluno do ensino básico), BÀI HỌC (lição)."},{"v":"Thường","p":"Normalmente / Geralmente","e":"Usually / Normally","c":"Advérbio","g":"THƯỜNG = 'normalmente' / 'geralmente' / 'costuma'. Posição: antes do verbo. Frase do PDF Horas: 'Em thường về nhà lúc mấy giờ?' (A que horas você normalmente vai para casa?). Escala de frequência: LUÔN LUÔN (sempre) → THƯỜNG (geralmente) → ĐÔI KHI (às vezes) → ÍT KHI (raramente) → KHÔNG BAO GIỜ (nunca). Exemplo: 'Tôi thường thức dậy lúc 6 giờ sáng.' (Geralmente acordo às 6 da manhã.)"},{"v":"Sớm","p":"Cedo","e":"Early","c":"Advérbio","g":"SỚM = cedo (antes do esperado ou antes de tarde). Frase do PDF Horas: 'Anh sẽ về nhà sớm' (Você vai para casa cedo). Combinações frequentes: VỀ NHÀ SỚM (chegar em casa cedo), THỨC DẬY SỚM (acordar cedo), ĐẾN SỚM (chegar cedo), NGỦ SỚM (dormir cedo). Oposto: MUỘN (tarde/atrasado). Compare: SỚM (cedo em relação ao horário esperado) vs NHANH (rápido em execução)."},{"v":"Quà","p":"Presente","e":"Gift / Present","c":"Substantivo","g":"QUÀ = presente (o objeto dado). TẶNG QUÀ = dar um presente (TẶNG = ato de presentear + QUÀ = o item). QUÀ SINH NHẬT = presente de aniversário. Frase do PDF Aniversário: 'Tặng quà sinh nhật' (dar presente de aniversário). Classificador: 'món' — 'một món quà' (um presente). Diferença essencial: QUÀ (o objeto) vs TẶNG (o verbo de dar). 'Quà này đẹp quá!' (Que presente bonito!)"},{"v":"Hà Nội","p":"Hanói (capital do Vietnã)","e":"Hanoi (capital of Vietnam)","c":"Nome","g":"HÀ NỘI = capital do Vietnã, cidade do Norte (dialeto estudado neste site). HÀ = lago/rio, NỘI = interior. Frase do PDF Aniversário: 'Bao giờ anh sẽ đi Hà Nội?' (Quando você vai a Hanói?). Contraste regional: HÀ NỘI (Norte) vs TP. HỒ CHÍ MINH / SÀI GÒN (Sul). Com ĐI para destino: 'Tôi sẽ đi Hà Nội' (Vou a Hanói). Com Ở para localização: 'Tôi đang ở Hà Nội' (Estou em Hanói)."},{"v":"Có thể","p":"Poder / Conseguir","e":"Can / Be able to","c":"Modal","g":"CÓ THỂ = modal de possibilidade/capacidade (equivalente a 'can' / poder). Estrutura: S + CÓ THỂ + VERBO: 'Tôi có thể nói tiếng Việt' (Eu consigo falar vietnamita). CÓ = ter/existir, THỂ = forma/jeito — juntos indicam capacidade. Negativa: 'không thể' (não pode/não consegue). Pergunta: 'Bạn có thể giúp tôi không?' (Você pode me ajudar?). Compare: PHẢI (ter que / obrigação) vs CÓ THỂ (poder / capacidade)."},{"v":"Tìm thấy","p":"Encontrar (objeto perdido)","e":"To find (lost objects)","c":"Verbo","g":"TÌM THẤY = encontrar algo que foi procurado — sempre para objetos perdidos ou buscados. TÌM = procurar + THẤY = conseguir ver/perceber. Resultado bem-sucedido: 'Tìm thấy' (encontrou). Sem resultado: 'Không tìm thấy' (não encontrou). Contraste ESSENCIAL: TÌM THẤY (encontrar OBJETOs / coisas) vs GẶP (encontrar PESSOAs). Erro comum: NÃO diga 'gặp chìa khóa' (encontrar a chave) — use sempre TÌM THẤY para objetos."},{"v":"Với","p":"Com (companhia / instrumento)","e":"With","c":"Preposição","g":"VỚI = preposição 'com', usada para: (1) COMPANHIA: 'Tôi đi với bạn' (Vou com você); (2) INSTRUMENTO: 'ăn với đũa' (comer com pauzinhos); (3) INTERAÇÃO: 'nói với anh ấy' (falar com ele). Posição: VERBO + VỚI + quem/o quê. Na fala coloquial VỚI também aparece como 'e' ligando ações. Compare: VỚI (com — companhia/instrumento) vs CÙNG (junto, enfatiza unidade): 'cùng nhau' (juntos)."},{"v":"Hiểu","p":"Entender / Compreender","e":"To understand","c":"Verbo","g":"HIỂU = entender, compreender (verbo de cognição). Tom hỏi (̉): curva suave descendente-ascendente. Frase mais usada: 'Tôi không hiểu' (Não entendo). Confirmação de entendimento: 'Hiểu rồi!' (Entendi! — RỒI = já, mudança de estado). Pergunta: 'Bạn hiểu không?' (Você entendeu?). Resposta positiva: 'Hiểu ạ' (Entendi, com respeito). Grau: 'hiểu rõ' (entender claramente), 'chưa hiểu' (ainda não entendi)."},{"v":"Tốt","p":"Bom / Boa / Bem","e":"Good / Well","c":"Adjetivo","g":"TỐT = bom/boa/bem — adjetivo positivo de QUALIDADE MORAL e UTILIDADE. Tom sắc (́): alto-crescente — 'tốt' soa agudo. Exemplos: 'người tốt' (boa pessoa), 'sức khỏe tốt' (saúde boa), 'học tốt' (estudar bem). DIFERENÇA com os outros 'bons': TỐT (bom moralmente/funcionalmente), NGON (bom de sabor — comida), HAY (bom de conteúdo — filme, livro), TUYỆT (ótimo — entusiasmo). 'Tốt quá!' (Que bom!) — forma exclamativa."},{"v":"Giúp","p":"Ajudar","e":"To help","c":"Verbo","g":"GIÚP = ajudar. Tom sắc (́): alto-crescente. Estrutura: S + GIÚP + pessoa + [ação/tarefa]: 'Anh giúp tôi được không?' (Você pode me ajudar?). Forma expandida: GIÚP ĐỠ (ajudar — formalidade) vs GIÚP (ajudar — uso hário). 'Tôi muốn giúp bạn' (Quero te ajudar). Forma de pedido educado: 'Bạn có thể giúp tôi không?' (combina CÓ THỂ + GIÚP). 'Cảm ơn bạn đã giúp tôi' (Obrigado por me ajudar)."},{"v":"Nói","p":"Falar / Dizer","e":"To speak / To say","c":"Verbo","g":"NÓI = falar, dizer. Tom sắc (́): alto-crescente. Usos principais: (1) FALAR um idioma: 'Nói tiếng Việt' (falar vietnamita); (2) DIZER algo: 'Anh nói gì?' (O que você disse?); (3) FALAR com alguém: 'Nói với tôi' (fale comigo — NÓI + VỚI). Diferença: NÓI (falar/dizer em geral) vs NÓI CHUYỆN (conversar — bate-papo) vs HỎI (perguntar) vs TRẢ LỜI (responder). Estrutura curso: 'Tôi đang học nói tiếng Việt' (Estou aprendendo a falar vietnamita)."},{"v":"Có ... không?","p":"Estrutura de pergunta sim/não","e":"Yes/no question structure","c":"Expressão","g":"CÓ ... KHÔNG? = estrutura para perguntas de sim ou não. Fórmula: S + CÓ + VERBO/ADJETIVO + KHÔNG? 'Bạn có học tiếng Việt không?' (Você estuda vietnamita?). Resposta SIM: 'Có' ou 'Vâng, có'. Resposta NÃO: 'Không'. O CÓ inicial pode ser omitido na fala informal: 'Bạn thích phở không?' = 'Bạn có thích phở không?'. CUIDADO: não confundir CÓ (partícula de pergunta) com CÓ (ter/existir): 'Có bạn gái không?' (Tem namorada?) — aqui CÓ = ter."}];

  // ── Category colors ───────────────────────────────────────────
  const COLORS = {
    'Verbo':         { bg: '#dbeafe', tx: '#1d4ed8' },
    'Substantivo':   { bg: '#d1fae5', tx: '#065f46' },
    'Adjetivo':      { bg: '#fce7f3', tx: '#9d174d' },
    'Adv\u00e9rbio': { bg: '#fef3c7', tx: '#92400e' },
    'Pronome':       { bg: '#ede9fe', tx: '#5b21b6' },
    'Express\u00e3o':{ bg: '#ffedd5', tx: '#9a3412' },
    'Sauda\u00e7\u00e3o': { bg: '#ecfdf5', tx: '#065f46' },
    'Part\u00edcula':{ bg: '#f0f9ff', tx: '#0369a1' },
    'Interrogativo': { bg: '#fff7ed', tx: '#c2410c' },
    'Conjun\u00e7\u00e3o': { bg: '#f5f3ff', tx: '#4c1d95' },
    'Demonstrativo': { bg: '#fef2f2', tx: '#991b1b' },
    'Classificador': { bg: '#f0fdf4', tx: '#166534' },
    'Confirma\u00e7\u00e3o': { bg: '#dcfce7', tx: '#14532d' },
    'Profiss\u00e3o': { bg: '#fffbeb', tx: '#78350f' },
    'Nome':          { bg: '#fdf4ff', tx: '#701a75' },
    'N\u00famero':   { bg: '#eff6ff', tx: '#1e40af' },
    'Modal':         { bg: '#fef9c3', tx: '#713f12' },
    'Preposi\u00e7\u00e3o': { bg: '#f1f5f9', tx: '#334155' },
    'Interjei\u00e7\u00e3o': { bg: '#fff1f2', tx: '#881337' },
  };

  // ── Persistent state ──────────────────────────────────────────
  const SK = '__vn_ov__';
  let isOpen = false, isMin = false, isPinned = false;
  let cat = 'Todos', q = '';
  let pos = { x: Math.max(10, window.innerWidth - 440), y: 80 };

  try {
    const s = JSON.parse(localStorage.getItem(SK) || '{}');
    if (typeof s.x === 'number') pos = { x: s.x, y: s.y };
    if (s.pinned) isPinned = true;
  } catch {}

  const save = () => {
    try { localStorage.setItem(SK, JSON.stringify({ x: pos.x, y: pos.y, pinned: isPinned })); } catch {}
  };

  // ── Shadow DOM host ───────────────────────────────────────────
  const host = document.createElement('div');
  host.id = ROOT_ID;
  host.style.cssText = 'all:initial;position:fixed!important;z-index:2147483647!important;top:0!important;left:0!important;width:0!important;height:0!important;overflow:visible!important;';

  const attach = () => { (document.body || document.documentElement).appendChild(host); };
  if (document.body) attach();
  else document.addEventListener('DOMContentLoaded', attach);

  let shadow;
  try { shadow = host.attachShadow({ mode: 'open' }); }
  catch { return; } // page doesn't allow shadow DOM

  // ── Styles ────────────────────────────────────────────────────
  const style = document.createElement('style');
  style.textContent = `
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    #pnl {
      position: fixed; width: 400px;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
      font-size: 14px; color: #0f172a;
      background: #ffffff; border: 1.5px solid #e2e8f0;
      border-radius: 12px; box-shadow: 0 20px 60px rgba(0,0,0,0.28);
      display: flex; flex-direction: column; overflow: hidden;
    }
    #pnl.pinned { border: 2px solid #4f46e5; }
    #hdr {
      background: #4f46e5; padding: 9px 12px;
      display: flex; align-items: center; gap: 6px;
      cursor: grab; user-select: none; flex-shrink: 0;
    }
    #hdr:active { cursor: grabbing; }
    #pnl.pinned #hdr { background: #3730a3; cursor: default; }
    #ttl { font-size: 13px; font-weight: 700; color: #fff; flex: 1; }
    .hb {
      background: rgba(255,255,255,0.2); border: none; color: #fff;
      cursor: pointer; border-radius: 5px; padding: 3px 8px;
      font-size: 12px; font-weight: 700; flex-shrink: 0; line-height: 1.4;
    }
    .hb:hover { background: rgba(255,255,255,0.35); }
    .hb.x { background: rgba(200,0,0,0.45); }
    .hb.x:hover { background: rgba(220,0,0,0.65); }
    #bdy {
      display: flex; flex-direction: column; gap: 8px;
      padding: 10px 12px 12px;
      max-height: min(500px, calc(100vh - 120px)); overflow: hidden;
    }
    #si {
      width: 100%; padding: 7px 12px; font-size: 13px; font-family: inherit;
      border: 1.5px solid #e2e8f0; border-radius: 9999px;
      background: #f8fafc; color: #0f172a; outline: none;
    }
    #si:focus { border-color: #818cf8; background: #fff; }
    #cats {
      display: flex; gap: 4px; overflow-x: auto;
      padding-bottom: 2px; scrollbar-width: none; flex-shrink: 0;
    }
    #cats::-webkit-scrollbar { display: none; }
    .cb {
      padding: 2px 8px; border-radius: 9999px; border: 1.5px solid #e2e8f0;
      background: #fff; color: #64748b; font-size: 10.5px; font-family: inherit;
      cursor: pointer; white-space: nowrap; flex-shrink: 0;
    }
    .cb.on { background: #4f46e5; color: #fff; border-color: #4f46e5; }
    #cnt { font-size: 11px; color: #94a3b8; flex-shrink: 0; }
    #res { overflow-y: auto; flex: 1; border: 1px solid #f1f5f9; border-radius: 8px; }
    table { width: 100%; border-collapse: collapse; font-size: 12.5px; }
    thead th {
      text-align: left; padding: 6px 10px; font-size: 10px;
      font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em;
      color: #94a3b8; border-bottom: 2px solid #e2e8f0; background: #f8fafc;
      position: sticky; top: 0; z-index: 1;
    }
    tbody tr { border-bottom: 1px solid #f1f5f9; cursor: default; }
    tbody tr:last-child { border-bottom: none; }
    tbody tr:hover td { background: #f0f4ff; }
    td { padding: 6px 10px; vertical-align: middle; }
    .vn { font-weight: 700; color: #4f46e5; }
    .badge {
      display: inline-block; padding: 2px 6px; border-radius: 9999px;
      font-size: 10px; font-weight: 600; white-space: nowrap;
    }
    #more { text-align: center; padding: 8px; font-size: 11px; color: #94a3b8; }
  `;
  shadow.appendChild(style);

  // ── Panel DOM ─────────────────────────────────────────────────
  const pnl = document.createElement('div');
  pnl.id = 'pnl';
  if (isPinned) pnl.classList.add('pinned');
  shadow.appendChild(pnl);

  pnl.innerHTML = `
    <div id="hdr">
      <span id="ttl">📚 Vocabulário VN</span>
      <button class="hb" id="bpin" title="Fixar posição">📍</button>
      <button class="hb" id="bmin" title="Minimizar">▼</button>
      <button class="hb x" id="bcls" title="Fechar (Ctrl+Shift+V)">✕</button>
    </div>
    <div id="bdy">
      <input id="si" type="text" placeholder="Buscar: vietnamita, português ou inglês..." autocomplete="off" spellcheck="false" />
      <div id="cats"></div>
      <div id="cnt"></div>
      <div id="res">
        <table>
          <thead><tr><th>Vietnamita</th><th>Português</th><th>Cat.</th></tr></thead>
          <tbody id="tb"></tbody>
        </table>
        <div id="more"></div>
      </div>
    </div>
  `;

  const $ = (id) => shadow.getElementById(id);
  const bdy = $('bdy'), si = $('si'), catsEl = $('cats');
  const cnt = $('cnt'), tb = $('tb'), more = $('more');
  const bpin = $('bpin'), bmin = $('bmin'), bcls = $('bcls');
  const hdr = $('hdr');

  // ── Category buttons ──────────────────────────────────────────
  const allCats = ['Todos', ...[...new Set(VOCAB.map(v => v.c))].sort()];
  allCats.forEach(c => {
    const b = document.createElement('button');
    b.className = 'cb' + (c === cat ? ' on' : '');
    b.textContent = c;
    b.addEventListener('click', () => { cat = c; renderCats(); renderRows(); });
    catsEl.appendChild(b);
  });

  function renderCats() {
    catsEl.querySelectorAll('.cb').forEach((b, i) => b.classList.toggle('on', allCats[i] === cat));
  }

  function renderRows() {
    const ql = q.toLowerCase();
    const filtered = VOCAB.filter(v => {
      const mq = !ql || v.v.toLowerCase().includes(ql) || v.p.toLowerCase().includes(ql) || (v.e && v.e.toLowerCase().includes(ql));
      return mq && (cat === 'Todos' || v.c === cat);
    });

    cnt.textContent = `${filtered.length} resultado${filtered.length !== 1 ? 's' : ''}`;
    tb.innerHTML = '';

    filtered.slice(0, 120).forEach(v => {
      const col = COLORS[v.c] || { bg: '#f1f5f9', tx: '#475569' };
      const tr = document.createElement('tr');
      tr.innerHTML = `
        <td class="vn">${v.v}</td>
        <td>${v.p}</td>
        <td><span class="badge" style="background:${col.bg};color:${col.tx}">${v.c}</span></td>
      `;
      if (v.g) tr.title = v.g;
      tb.appendChild(tr);
    });

    more.textContent = filtered.length > 120 ? `+${filtered.length - 120} resultados — refine a busca` : '';
  }

  // ── Position / drag ───────────────────────────────────────────
  const applyPos = () => {
    pnl.style.left = Math.max(0, Math.min(pos.x, window.innerWidth  - 410)) + 'px';
    pnl.style.top  = Math.max(0, Math.min(pos.y, window.innerHeight -  60)) + 'px';
  };
  applyPos();

  let drag = null;
  hdr.addEventListener('mousedown', e => {
    if (isPinned || e.button !== 0) return;
    e.preventDefault(); e.stopPropagation();
    drag = { mx: e.clientX, my: e.clientY, px: pos.x, py: pos.y };
  });
  document.addEventListener('mousemove', e => {
    if (!drag) return;
    pos.x = drag.px + (e.clientX - drag.mx);
    pos.y = drag.py + (e.clientY - drag.my);
    applyPos();
  }, true);
  const stopDrag = () => { if (drag) { drag = null; save(); } };
  document.addEventListener('mouseup', stopDrag, true);
  window.addEventListener('blur', stopDrag);

  // ── Open / close / minimize / pin ────────────────────────────
  function setOpen(v) {
    isOpen = v;
    pnl.style.display = v ? 'flex' : 'none';
    if (v) { renderRows(); setTimeout(() => si.focus(), 60); }
  }
  function setMin(v) {
    isMin = v;
    bdy.style.display = v ? 'none' : 'flex';
    bmin.textContent = v ? '▲' : '▼';
  }
  function setPin(v) {
    isPinned = v;
    pnl.classList.toggle('pinned', v);
    bpin.textContent = v ? '📌' : '📍';
    bpin.title = v ? 'Desafixar (pode arrastar)' : 'Fixar posição';
    save();
  }

  bcls.addEventListener('click', e => { e.stopPropagation(); setOpen(false); });
  bmin.addEventListener('click', e => { e.stopPropagation(); setMin(!isMin); });
  bpin.addEventListener('click', e => { e.stopPropagation(); setPin(!isPinned); });
  si.addEventListener('input', e => { q = e.target.value; renderRows(); });

  // ── Keyboard shortcut (Ctrl+Shift+V) ─────────────────────────
  document.addEventListener('keydown', e => {
    if (e.ctrlKey && e.shiftKey && (e.key === 'V' || e.key === 'v')) {
      e.preventDefault(); e.stopPropagation();
      setOpen(!isOpen);
    }
  }, true);

  // ── Chrome extension icon click (via background.js message) ──
  if (typeof chrome !== 'undefined' && chrome.runtime && chrome.runtime.onMessage) {
    chrome.runtime.onMessage.addListener(msg => {
      if (msg && msg.action === 'toggle') setOpen(!isOpen);
    });
  }

  // Start closed
  setOpen(false);
})();
